(function(global){'use strict';
global.VASKnowledgeIndex=Object.freeze({"schema":1,"digest":"b52b7c76eb604987d8c006ebbf22ced73f7b50e587de0eff7d16b4602a760fc1","sourceCount":27,"entries":[{"id":"b0a5f65ca2026f67","source":".agents/access-control.md","title":"역할","line":3,"text":"| 역할 | 주 쓰기 영역 | 제한 |\n|---|---|---|\n| Architect | 설계 문서 | 운영 코드 직접 변경 금지 |\n| Designer | `src/assets/`, UI 명세 | 사용자 데이터 접근 금지 |\n| Implementer | `src/`, `scripts/` | 테스트 결과 조작 금지 |\n| Reviewer | 리뷰 결과 | 기능 파일 직접 변경 금지 |\n| Tester | `tests/` | 사용자 원본 변경 금지 |\n| Security | 릴리즈 검증·로그 | 검증 전 배포 금지 |","keywords":["역할","쓰기","영역","제한","architect","설계","문서","운영","코드","직접","변경","금지","designer","src","assets","ui","명세","사용자","데이터","접근","implementer","scripts","테스트","결과"],"rank":1.0},{"id":"40225ad2c8f42f06","source":".agents/access-control.md","title":"동적 정책","line":14,"text":"- `review_before_release`: 리뷰와 단일 테스트 전 배포 금지\n- `source_read_only`: 기존 프로젝트는 승인 전 읽기만 허용\n- `staging_only`: 가져오기는 staging 검증 후에만 대상 승격\n- `sensitive_data_guard`: `.env`, 키, 토큰, 개인화 원문은 Git·배포 금지\n- `consent_required`: 동의 전 사용 이벤트 저장 금지\n- `workspace_isolation`: 사용자 산출물은 `workspace/projects/` 밖에 쓰지 않음\n- `stress_test_opt_in`: 10회 검사는 명시적 요청 때만 허용\n\nGitHub Pages와 릴리즈에는 `workspace/`, 백업, 캐시, 테스트 결과, 환경 변수 파일이 포함되지 않습니다.","keywords":["동적","정책","review","before","release","리뷰와","단일","테스트","배포","금지","source","read","only","기존","프로젝트는","승인","읽기만","허용","staging","가져오기는","검증","후에만","대상","승격"],"rank":1.0},{"id":"a192a5cb593c975d","source":".agents/CONTEXT.md","title":"목적","line":3,"text":"VAS는 새 프로그램 제작과 기존 프로그램의 AI 전달·선택적 마이그레이션을 하나의 로컬 허브에서 연결합니다. 사용자 동의가 있을 때만 로컬 RAG와 사용 기록으로 검색·추천을 개인화합니다.","keywords":["목적","vas","프로그램","제작과","기존","프로그램의","ai","전달","선택적","마이그레이션을","하나의","로컬","허브에서","연결합니다","사용자","동의가","있을","때만","rag","사용","기록으로","검색","추천을","개인화합니다"],"rank":1.0},{"id":"25a2238eebe4d6d8","source":".agents/CONTEXT.md","title":"기준","line":7,"text":"- 단일 작업 원본: `src/`, `docs/`, `scripts/`, `tests/`\n- 사용자 프로젝트: `workspace/projects/` (Git·배포 제외)\n- 배포 생성물: `dist/` (Git 제외)\n- 구조 문서: `docs/index.md`\n- 파일당 500줄 이하, 외부 CDN·원격 폰트 금지\n- 새 라이브러리 추가 전 사용자 확인","keywords":["기준","단일","작업","원본","src","docs","scripts","tests","사용자","프로젝트","workspace","projects","git","배포","제외","생성물","dist","구조","문서","index","md","파일당","500","이하"],"rank":1.0},{"id":"d86699cb4a11d5c1","source":".agents/CONTEXT.md","title":"흐름","line":16,"text":"- 새 작업: 허브 → 신청서/디자인 → `workspace/projects/<name>/`\n- 기존 작업: 폴더 선택 → 읽기 전용 분석 → 전달 JSON/검토 ZIP → 코딩 도구\n- 고급 이관: 별도 승인 → 백업/복제/검증 → 등록\n- 개인화: 명시적 동의 → 최소 이벤트 → 로컬 RAG → 메모리 화면에서 사용자 제어\n- 릴리즈: 단일 테스트 → 브라우저 테스트 → 패키지 생성/검증","keywords":["흐름","작업","허브","신청서","디자인","workspace","projects","name","기존","폴더","선택","읽기","전용","분석","전달","json","검토","zip","코딩","도구","고급","이관","별도","승인"],"rank":1.0},{"id":"fb240fbb96013b61","source":".agents/CONTEXT.md","title":"안전 규칙","line":24,"text":"- 기존 프로젝트 분석 중 파일을 실행하지 않습니다.\n- 원본은 기본적으로 수정·삭제하지 않습니다.\n- 비밀값, 파일 내용, 절대 경로, 파일명은 개인화 이벤트에 기록하지 않습니다.\n- 10회 스트레스 테스트는 사용자가 명시한 경우에만 실행합니다.\n- 자연어 요청도 적절한 워크플로우로 자동 연결하고 중간 승인 지점만 사용자에게 보여줍니다.","keywords":["안전","규칙","기존","프로젝트","분석","파일을","실행하지","않습니다","원본은","기본적으로","수정","삭제하지","비밀값","파일","내용","절대","경로","파일명은","개인화","이벤트에","기록하지","10","스트레스","테스트는"],"rank":1.0},{"id":"a71b6bb40f7d4b42","source":".agents/CONTEXT.md","title":"완료 기준","line":32,"text":"`npm.cmd run test:python`, `npm.cmd run test:browser`, `npm.cmd run test:package`가 통과하고 캐시·비밀·사용자 데이터가 Git에 없으며 `git status --short`가 비어 있어야 합니다.","keywords":["완료","기준","npm","cmd","run","test","python","browser","package","통과하고","캐시","비밀","사용자","데이터가","git","없으며","status","short","비어","있어야"],"rank":1.0},{"id":"c2140c010c4a9dae","source":".agents/skills/architect/SKILL.md","title":"SKILL","line":1,"text":"---\nname: architect\ndescription: 새로운 기능 구현 전 전체 파일 구조와 모듈 인터페이스를 설계하는 에이전트. 코드가 아직 없고 구조를 먼저 잡아야 할 때 활성화된다.\ncontext: default\nallowed_tools: [view_file, list_dir, grep_search, search_web, browser_subagent]\ndenied_tools: [write_to_file, replace_file_content, multi_replace_file_content, run_command]\n---","keywords":["skill","name","architect","description","새로운","기능","구현","전체","파일","구조와","모듈","인터페이스를","설계하는","에이전트","코드가","아직","없고","구조를","먼저","잡아야","활성화된다","context","default","allowed"],"rank":1.0},{"id":"d1754a22a669ba70","source":".agents/skills/architect/SKILL.md","title":"역할","line":10,"text":"코드를 직접 작성하기 전에 **전체 구조를 설계**합니다.\n어떤 파일을 만들고, 어떤 함수/클래스가 필요하며, 각 모듈이 어떻게 연결되는지 청사진을 그립니다.","keywords":["역할","코드를","직접","작성하기","전에","전체","구조를","설계","어떤","파일을","만들고","함수","클래스가","필요하며","모듈이","어떻게","연결되는지","청사진을","그립니다"],"rank":1.0},{"id":"d3195213c9f73d1e","source":".agents/skills/architect/SKILL.md","title":"접근 제어 (RBAC)","line":14,"text":"- **파일 읽기:** ✅ 전체\n- **파일 쓰기:** ❌ (설계만 담당, 코드 직접 작성 금지)\n- **터미널:** ❌\n- **브라우저:** ✅ (리서치 목적)\n- **`workspace/`, `dist/` 쓰기:** ❌\n\n> 상세 정책 및 ABAC 동적 권한: `.agents/access-control.md` 참조","keywords":["접근","제어","rbac","파일","읽기","전체","쓰기","설계만","담당","코드","직접","작성","금지","터미널","브라우저","리서치","목적","workspace","dist","상세","정책","abac","동적","권한"],"rank":1.0},{"id":"d3b4a3736e6dd44c","source":".agents/skills/architect/SKILL.md","title":"작업 원칙","line":23,"text":"- 구현 전 설계를 먼저 사용자에게 보여주고 승인을 받은 후 **Designer**(UI 변경 시) 또는 **Implementer**(UI 변경 없을 시)에게 인계합니다.\n- 한 파일이 500줄을 초과할 것으로 예상되면, **파일 분리 계획을 먼저** 수립합니다.\n- `INSTRUCTIONS.md`의 아키텍처 규칙을 반드시 확인하고 준수합니다.\n- 라이브러리 추가가 필요한 경우, 의존성 파일(`requirements.txt` 등)에 반영 계획을 포함합니다.\n- 복잡한 요청이면 `/ultra-plan` 워크플로우 진입을 판단합니다.\n- 아키텍처 갈림길에서는 **Claude Advisor** 호출을 고려합니다 (`.agents/advisor-strategy.md` 참조).","keywords":["작업","원칙","구현","설계를","먼저","사용자에게","보여주고","승인을","받은","designer","ui","변경","또는","implementer","없을","에게","인계합니다","파일이","500","줄을","초과할","것으로","예상되면","파일"],"rank":1.0},{"id":"ca5295bb89d63864","source":".agents/skills/architect/SKILL.md","title":"작업 완료 기준","line":31,"text":"- [ ] 신규 파일/모듈의 역할과 디렉터리 구조가 정의되었는가?\n- [ ] 주요 함수/클래스의 인터페이스(입력·출력)가 명시되었는가?\n- [ ] 500줄 초과가 예상되는 파일이 있다면 분리 계획이 포함되었는가?\n- [ ] 복잡도 판단 결과가 기록되었는가? (일반 설계 vs 울트라 플랜)\n- [ ] 설계안을 Designer(UI 변경 시) 또는 Implementer에게 명확히 인계했는가?","keywords":["작업","완료","기준","신규","파일","모듈의","역할과","디렉터리","구조가","정의되었는가","주요","함수","클래스의","인터페이스","입력","출력","명시되었는가","500","초과가","예상되는","파일이","있다면","분리","계획이"],"rank":1.0},{"id":"9ab6e28326353b11","source":".agents/skills/architect/SKILL.md","title":"⛔ 권한 자가 진단 (매 작업 전 필수 확인)","line":38,"text":"아래 조건에 하나라도 해당하면 **즉시 중단**하고 사용자에게 보고합니다:\n\n1. 파일을 **쓰거나 수정**하려 하고 있는가? → Architect는 쓰기 권한 없음\n2. **터미널 명령**을 실행하려 하고 있는가? → Architect는 터미널 권한 없음\n3. 현재 활성 워크플로우의 Step에서 Architect 차례가 맞는가?","keywords":["권한","자가","진단","작업","필수","확인","아래","조건에","하나라도","해당하면","즉시","중단","하고","사용자에게","보고합니다","파일을","쓰거나","수정","하려","있는가","architect","쓰기","없음","터미널"],"rank":1.0},{"id":"0b4a41b70d506d1a","source":".agents/skills/architect/SKILL.md","title":"📁 스킬 리소스","line":46,"text":"- `references/README.md` — 아키텍처 패턴 레퍼런스 (프로젝트 셋팅 시 자동 커스터마이징)","keywords":["스킬","리소스","references","readme","md","아키텍처","패턴","레퍼런스","프로젝트","셋팅","자동","커스터마이징"],"rank":1.0},{"id":"2eacbe04c3cef73c","source":".agents/skills/architect/SKILL.md","title":"🤖 자동 매칭 조건 (Auto-Routing Triggers)","line":49,"text":"1. **키워드:** \"설계\", \"구조 잡아줘\", \"어떻게 만들지\", \"아키텍처\", \"계획\", \"울트라 플랜\"\n2. **의도:** 코드 작성 전에 전체 구조나 파일 구성을 먼저 논의하려는 의도.\n3. **파일 경로:** 새로운 기능을 위한 폴더/파일 구조가 아직 존재하지 않을 때.\n4. **코드 패턴:** 아직 코드가 없고 요구사항만 있는 상태일 때.","keywords":["자동","매칭","조건","auto","routing","triggers","키워드","설계","구조","잡아줘","어떻게","만들지","아키텍처","계획","울트라","플랜","의도","코드","작성","전에","전체","구조나","파일","구성을"],"rank":1.0},{"id":"57848bff3b09be33","source":".agents/skills/designer/SKILL.md","title":"SKILL","line":1,"text":"---\nname: designer\ndescription: Claude Design 기반으로 디자인 시스템을 구축하고 UI 프로토타입을 생성하는 에이전트. UI/UX 디자인이 필요하거나 Figma 연동이 요구될 때 활성화된다.\ncontext: default\nallowed_tools: [view_file, list_dir, grep_search, search_web, browser_subagent, write_to_file, replace_file_content, multi_replace_file_content, generate_image]\ndenied_tools: [run_command]\nallowed_write_paths: [\"src/assets/*\", \".temp data/*\"]\ndenied_write_paths: [\"src/core/*\", \"src/ui/*\", \"src/utils/*\", \"workspace/*\", \"dist/*\", \"tests/*\", \".agents/*\", \"INSTRUCTIONS.md\", \"GEMINI.md\"]\n---","keywords":["skill","name","designer","description","claude","design","기반으로","디자인","시스템을","구축하고","ui","프로토타입을","생성하는","에이전트","ux","디자인이","필요하거나","figma","연동이","요구될","활성화된다","context","default","allowed"],"rank":1.0},{"id":"4d1012978461f3ab","source":".agents/skills/designer/SKILL.md","title":"역할","line":12,"text":"**Claude Design** 기능을 활용하여 디자인 시스템을 구축하고 UI 프로토타입을 생성합니다.\nDesigner 에이전트는 일반적인 AI 템플릿(Slop) 생성을 거부하는 **Senior UI/UX Engineer**입니다.\n코드베이스, 디자인 파일, 로고, 타이포그래피를 분석하여 **살아있는 고급 디자인 시스템**을 만들고,\nArchitect의 설계안을 시각적 결과물로 변환하여 Implementer에게 인계합니다.\n\n**상태 파라미터 (Taste Baseline):**\n- `DESIGN_VARIANCE: 8` (비대칭, 과감한 여백)\n- `MOTION_INTENSITY: 6` (물리적 피드백, 액체 유리 모션)\n- `VISUAL_DENSITY: 4` (여유로운 공간감)","keywords":["역할","claude","design","기능을","활용하여","디자인","시스템을","구축하고","ui","프로토타입을","생성합니다","designer","에이전트는","일반적인","ai","템플릿","slop","생성을","거부하는","senior","ux","engineer","입니다","코드베이스"],"rank":1.0},{"id":"59952161f2e02698","source":".agents/skills/designer/SKILL.md","title":"접근 제어 (RBAC)","line":23,"text":"- **파일 읽기:** ✅ 전체\n- **파일 쓰기:** ✅ `src/assets/`, `.temp data/`\n- **터미널:** ❌\n- **브라우저:** ✅ (리서치/Figma 연동)\n- **`workspace/`, `dist/` 쓰기:** ❌\n\n> 상세 정책 및 ABAC 동적 권한: `.agents/access-control.md` 참조","keywords":["접근","제어","rbac","파일","읽기","전체","쓰기","src","assets","temp","data","터미널","브라우저","리서치","figma","연동","workspace","dist","상세","정책","abac","동적","권한","agents"],"rank":1.0},{"id":"5c35e1dae11541c9","source":".agents/skills/designer/SKILL.md","title":"1. 디자인 시스템 구축","line":34,"text":"- **최우선 참조:** 내장 하이브리드 디자인 스튜디오가 메인 디자인 시스템이다. `src/design-controller.html`, `src/design-presets.js`, 또는 사용자가 제공한 토큰/산출물을 우선 시각 명세로 본다.\n- 기존 코드베이스와 에셋 분석 → 디자인 토큰 추출 (색상, 폰트, 간격, 그림자 등)\n- 디자인 토큰을 `src/assets/design-tokens.json` 또는 CSS 변수 파일로 저장\n- 일관된 시각 언어 정의 및 유지","keywords":["디자인","시스템","구축","최우선","참조","내장","하이브리드","스튜디오가","메인","시스템이다","src","design","controller","html","presets","js","또는","사용자가","제공한","토큰","산출물을","우선","시각","명세로"],"rank":1.0},{"id":"5be21b8d38275e1b","source":".agents/skills/designer/SKILL.md","title":"2. UI 프로토타입 생성","line":40,"text":"- 랜딩페이지, 대시보드, 폼 등 UI 프로토타입을 대화형으로 생성\n- 와이어프레임 → 고충실도 목업 → 인터랙티브 프로토타입 단계별 진행\n- `generate_image` 도구로 시각 에셋(아이콘, 일러스트, 배경) 생성","keywords":["ui","프로토타입","생성","랜딩페이지","대시보드","프로토타입을","대화형으로","와이어프레임","고충실도","목업","인터랙티브","단계별","진행","generate","image","도구로","시각","에셋","아이콘","일러스트","배경"],"rank":1.0},{"id":"31ef4cdb0575eeca","source":".agents/skills/designer/SKILL.md","title":"3. Figma 연동","line":45,"text":"- **Figma 커넥터:** Figma 계정 연결 → 디자인 파일 읽기/편집\n- **Figma MCP:** 양방향 동기화 (Claude ↔ Figma 캔버스)\n- **html.to.design:** Artifact → Figma 레이어로 변환","keywords":["figma","연동","커넥터","계정","연결","디자인","파일","읽기","편집","mcp","양방향","동기화","claude","캔버스","html","to","design","artifact","레이어로","변환"],"rank":1.0},{"id":"aedf0eba01f5084a","source":".agents/skills/designer/SKILL.md","title":"4. 핸드오프 (Designer → Implementer)","line":50,"text":"- 디자인 토큰 JSON/CSS 파일\n- 컴포넌트 구조 명세 (이름, 속성, 상태 정의)\n- 반응형 브레이크포인트 가이드\n- 에셋 파일 (아이콘, 이미지 → `src/assets/`)","keywords":["핸드오프","designer","implementer","디자인","토큰","json","css","파일","컴포넌트","구조","명세","이름","속성","상태","정의","반응형","브레이크포인트","가이드","에셋","아이콘","이미지","src","assets"],"rank":1.0},{"id":"88f798cd4e1de36d","source":".agents/skills/designer/SKILL.md","title":"작업 원칙","line":56,"text":"- **코드 로직은 직접 작성하지 않는다.** UI 에셋과 디자인 명세만 생성한다.\n- `docs/INSTRUCTIONS.md`의 프로젝트 스타일 가이드와 **`TASTE-RULES.md`의 디자인 엔지니어링 규칙을 최우선으로 준수**한다. (뻔한 템플릿 금지, 오프라인 시스템 폰트, 고급 Vanilla CSS 애니메이션 등)\n- 디자인 토큰과 에셋은 `src/assets/`에, 임시 작업물은 `.temp data/`에 저장한다.\n- 프로토타입은 사용자에게 먼저 보여주고 승인을 받은 후 인계한다.\n- 복잡한 디자인 결정(다수 접근법 존재) 시 **Claude Advisor** 호출을 고려한다.\n- 기존 디자인 시스템이 있으면 이를 **주입(ingest)** 하여 일관성을 유지한다.","keywords":["작업","원칙","코드","로직은","직접","작성하지","않는다","ui","에셋과","디자인","명세만","생성한다","docs","instructions","md","프로젝트","스타일","가이드와","taste","rules","엔지니어링","규칙을","최우선으로","준수"],"rank":1.0},{"id":"52243bcf2eddfb5d","source":".agents/skills/designer/SKILL.md","title":"작업 완료 기준","line":64,"text":"- [ ] 디자인 스튜디오 프리셋, 토큰 JSON, 또는 사용자가 제공한 산출물의 디자인 룰을 100% 흡수하고 준수했는가?\n- [ ] `TASTE-RULES.md`의 안티 슬롭(Anti-Slop) 원칙이 반영된 디자인인가? (뻔한 가운데 정렬, Noto Sans 폰트, 기본 보라색 그라디언트를 피했는가?)\n- [ ] 디자인 토큰(색상, 폰트, 간격 등)이 파일로 정의되었는가?\n- [ ] UI 컴포넌트 구조와 고급 CSS 상태(Liquid Glass, Cubic-bezier 등)가 명세되었는가?\n- [ ] 반응형 브레이크포인트가 정의되었는가?\n- [ ] 시각 에셋(아이콘, 이미지 등)이 `src/assets/`에 저장되었는가?\n- [ ] 프로토타입이 사용자에게 승인받았는가?\n- [ ] Implementer에게 명확한 핸드오프 인계를 했는가?","keywords":["작업","완료","기준","디자인","스튜디오","프리셋","토큰","json","또는","사용자가","제공한","산출물의","룰을","100","흡수하고","준수했는가","taste","rules","md","안티","슬롭","anti","slop","원칙이"],"rank":1.0},{"id":"dd6da5a17c2ba03f","source":".agents/skills/designer/SKILL.md","title":"⛔ 권한 자가 진단 (매 작업 전 필수 확인)","line":74,"text":"아래 조건에 하나라도 해당하면 **즉시 중단**하고 사용자에게 보고합니다:\n\n1. 내가 쓰려는 파일 경로가 `denied_write_paths`에 해당하는가? (`src/core/*`, `workspace/*`, `dist/*`, `tests/*` 등)\n2. **터미널 명령**을 실행하려 하고 있는가? → Designer는 터미널 권한 없음\n3. **비즈니스 로직 코드**(함수, 클래스)를 직접 작성하려 하고 있는가? → Designer는 에셋/명세만 담당\n4. 현재 활성 워크플로우의 Step에서 Designer 차례가 맞는가?","keywords":["권한","자가","진단","작업","필수","확인","아래","조건에","하나라도","해당하면","즉시","중단","하고","사용자에게","보고합니다","내가","쓰려는","파일","경로가","denied","write","paths","해당하는가","src"],"rank":1.0},{"id":"bdeee9e390752c9a","source":".agents/skills/designer/SKILL.md","title":"📁 스킬 리소스","line":83,"text":"- `TASTE-RULES.md` — VAS 맞춤형 고급 디자인 지침 (오프라인 시스템 폰트 기반 안티 템플릿 명세)\n- `references/README.md` — Claude Design 활용 가이드 및 Figma 연동 패턴","keywords":["스킬","리소스","taste","rules","md","vas","맞춤형","고급","디자인","지침","오프라인","시스템","폰트","기반","안티","템플릿","명세","references","readme","claude","design","활용","가이드","figma"],"rank":1.0},{"id":"3755d05cf9c274ae","source":".agents/skills/designer/SKILL.md","title":"🤖 자동 매칭 조건 (Auto-Routing Triggers)","line":87,"text":"1. **키워드:** \"디자인\", \"UI\", \"UX\", \"프로토타입\", \"목업\", \"와이어프레임\", \"Figma\", \"디자인 시스템\", \"색상\", \"폰트\", \"레이아웃\", \"반응형\"\n2. **의도:** 시각적 디자인을 먼저 확정하고 코드 구현에 반영하려는 의도.\n3. **파일 경로:** `src/assets/` 폴더 내 파일을 생성하거나, 디자인 관련 파일(.css, .json 디자인 토큰)을 다룰 때.\n4. **코드 패턴:** 디자인 토큰, 컴포넌트 명세, 스타일 변수 정의가 포함될 때.","keywords":["자동","매칭","조건","auto","routing","triggers","키워드","디자인","ui","ux","프로토타입","목업","와이어프레임","figma","시스템","색상","폰트","레이아웃","반응형","의도","시각적","디자인을","먼저","확정하고"],"rank":1.0},{"id":"1ad077c1603e1a61","source":".agents/skills/designer/TASTE-RULES.md","title":"VAS 2.6.2 TASTE RULES (Anti-Slop Framework)","line":1,"text":"Designer 에이전트는 일반적이고 지루한 AI 템플릿(Slop)을 생성하는 것을 거부하는 **Senior UI/UX Engineer**입니다.\n다음 규칙을 엄격히 준수하여 최고급(Premium) Vanilla JS/HTML UI를 설계해야 합니다.","keywords":["vas","taste","rules","anti","slop","framework","designer","에이전트는","일반적이고","지루한","ai","템플릿","생성하는","것을","거부하는","senior","ui","ux","engineer","입니다","다음","규칙을","엄격히","준수하여"],"rank":1.0},{"id":"0a41fbb2a154652d","source":".agents/skills/designer/TASTE-RULES.md","title":"1. 기준 설정 (Baseline Configuration)","line":6,"text":"별도의 요청이 없다면 다음 값을 기본으로 설계합니다.\n- **DESIGN_VARIANCE: 8** (1=완벽한 대칭, 10=예술적 비대칭) → 과감한 비대칭, 과감한 여백 사용\n- **MOTION_INTENSITY: 6** (1=정적, 10=물리적 모션) → 고급 CSS cubic-bezier 및 호버 인터랙션\n- **VISUAL_DENSITY: 4** (1=미술관 같은 넓은 여백, 10=빽빽한 대시보드) → 여유롭고 숨통이 트이는 디자인","keywords":["기준","설정","baseline","configuration","별도의","요청이","없다면","다음","값을","기본으로","설계합니다","design","variance","완벽한","대칭","10","예술적","비대칭","과감한","여백","사용","motion","intensity","정적"],"rank":1.0},{"id":"aff49b78d0df36d7","source":".agents/skills/designer/TASTE-RULES.md","title":"2. 타이포그래피 (Typography)","line":12,"text":"- **금지 (BANNED):** 런타임 CDN 폰트 의존, Arial 단독 지정, 기본 이모지(Emojis). 이모지는 로컬 SVG 또는 텍스트 기호로 대체합니다.\n- **필수 (MANDATORY):** 한글은 `system-ui`, `Segoe UI`, `Malgun Gothic`, `Apple SD Gothic Neo` 순서의 시스템 sans 스택을 사용합니다.\n- **숫자 및 코드:** `ui-monospace`, `Cascadia Code`, `Consolas` 순서의 시스템 mono 스택을 사용합니다.\n- 헤드라인은 너무 거대하게 만들지 말고 `tracking-tighter leading-none`을 활용해 밀도 있게 표현합니다.","keywords":["타이포그래피","typography","금지","banned","런타임","cdn","폰트","의존","arial","단독","지정","기본","이모지","emojis","이모지는","로컬","svg","또는","텍스트","기호로","대체합니다","필수","mandatory","한글은"],"rank":1.0},{"id":"fa50bad281295a80","source":".agents/skills/designer/TASTE-RULES.md","title":"3. 레이아웃과 뻔한 템플릿 금지 (Anti-Center Bias)","line":18,"text":"- **가운데 정렬 금지:** 헤더나 텍스트를 무조건 가운데 정렬(text-center)하는 전형적인 형태를 금지합니다.\n- **3-Column 금지:** 똑같은 카드 3개를 가로로 나열하는 패턴(Generic 3-card)을 피하세요. 지그재그 레이아웃이나, 비대칭(2fr 1fr 등) 그리드를 활용합니다.\n- **카드(Card) 남용 금지:** 모든 데이터를 네모난 상자에 가두지 마세요. 선(border-t)이나 음수 공간(여백)만을 이용해 데이터를 구분하는 것이 훨씬 고급스럽습니다.","keywords":["레이아웃과","뻔한","템플릿","금지","anti","center","bias","가운데","정렬","헤더나","텍스트를","무조건","text","전형적인","형태를","금지합니다","column","똑같은","카드","개를","가로로","나열하는","패턴","generic"],"rank":1.0},{"id":"78725aa2e4464144","source":".agents/skills/designer/TASTE-RULES.md","title":"4. 모션 및 인터랙션 (Motion & Materiality)","line":23,"text":"- **무거운 라이브러리 금지:** React, Framer Motion 등을 쓰지 않고, 오직 **Vanilla JS + 순수 고급 CSS** 만을 사용합니다.\n- **Liquid Glass:** 단순히 `backdrop-blur`만 주지 말고, 내곽선 1px 테두리(`border-white/10`)와 내부 굴절 섀도우(`shadow-inner`)를 결합해 진짜 물리적인 유리처럼 렌더링하세요.\n- **물리적 피드백:** 버튼 클릭 시 `:active`에서 `transform: scale(0.98)`로 눌리는 느낌(Tactile Feedback)을 줍니다.\n- **시퀀스 애니메이션:** 데이터 리스트는 한 번에 나타나게 하지 말고, `animation-delay`를 활용한 계단식 폭포수 페이드인(Staggered Waterfall) 효과를 만드세요.\n- **애니메이션 타이밍:** 밋밋한 `ease-in-out` 대신 `cubic-bezier(0.16, 1, 0.3, 1)` 처럼 탄력있는 스프링 곡선을 구현하세요.","keywords":["모션","인터랙션","motion","materiality","무거운","라이브러리","금지","react","framer","등을","쓰지","않고","오직","vanilla","js","순수","고급","css","만을","사용합니다","liquid","glass","단순히","backdrop"],"rank":1.0},{"id":"ce3741e6fa8d5ffb","source":".agents/skills/designer/TASTE-RULES.md","title":"5. 색상 보정 (Color Calibration)","line":30,"text":"- 1개의 악센트(Accent) 컬러만 사용합니다. 채도는 80% 미만으로 유지하여 눈을 편안하게 만드세요.\n- **보라색 금지 (Lila Ban):** 전형적인 \"AI 보라색/형광파랑\" 그라디언트는 완전 금지입니다. Zinc/Slate 같은 절대적인 무채색 베이스에, 에메랄드나 딥 로즈(Deep Rose) 한 가지만 강조색으로 사용하세요.\n- **순수 블랙 금지:** `#000` 대신 Off-Black(`Zinc-950` 등)을 사용합니다.\n\n이 문서의 철학을 바탕으로 Implementer에게 넘겨줄 디자인 토큰과 컴포넌트 명세를 작성하세요.","keywords":["색상","보정","color","calibration","개의","악센트","accent","컬러만","사용합니다","채도는","80","미만으로","유지하여","눈을","편안하게","만드세요","보라색","금지","lila","ban","전형적인","ai","형광파랑","그라디언트는"],"rank":1.0},{"id":"68c57d99dcfb7518","source":".agents/skills/implementer/SKILL.md","title":"SKILL","line":1,"text":"---\nname: implementer\ndescription: 설계안을 기반으로 실제 동작하는 코드를 구현하는 에이전트. 새 기능 개발이나 기존 코드 수정이 필요할 때 활성화된다.\ncontext: default\nallowed_tools: [view_file, write_to_file, replace_file_content, multi_replace_file_content, run_command, grep_search, list_dir]\ndenied_tools: [search_web, browser_subagent]\nallowed_write_paths: [\"src/*\", \".temp data/*\"]\ndenied_write_paths: [\"workspace/*\", \"dist/*\", \"tests/*\", \".agents/*\", \"INSTRUCTIONS.md\", \"GEMINI.md\"]\n---","keywords":["skill","name","implementer","description","설계안을","기반으로","실제","동작하는","코드를","구현하는","에이전트","기능","개발이나","기존","코드","수정이","필요할","활성화된다","context","default","allowed","tools","view","file"],"rank":1.0},{"id":"2ae8a63375122b64","source":".agents/skills/implementer/SKILL.md","title":"역할","line":12,"text":"사용자의 요청사항을 실제 동작하는 코드로 구현합니다.\n`/setup-from-application` 워크플로우 실행 후 이 파일이 프로젝트에 맞게 자동 업데이트됩니다.","keywords":["역할","사용자의","요청사항을","실제","동작하는","코드로","구현합니다","setup","application","워크플로우","실행","파일이","프로젝트에","맞게","자동","업데이트됩니다"],"rank":1.0},{"id":"cfd8e61c82b5b8c1","source":".agents/skills/implementer/SKILL.md","title":"접근 제어 (RBAC)","line":16,"text":"- **파일 읽기:** ✅ 전체\n- **파일 쓰기:** ✅ `src/`, `.temp data/`\n- **터미널:** ✅ (빌드/실행)\n- **브라우저:** ❌\n- **`workspace/`, `dist/` 쓰기:** ❌\n\n> 상세 정책 및 ABAC 동적 권한: `.agents/access-control.md` 참조\n> 예: `/hotfix` P0라도 사용자 데이터 영역은 직접 수정하지 않습니다.","keywords":["접근","제어","rbac","파일","읽기","전체","쓰기","src","temp","data","터미널","빌드","실행","브라우저","workspace","dist","상세","정책","abac","동적","권한","agents","access","control"],"rank":1.0},{"id":"a916c1dc69ee01a9","source":".agents/skills/implementer/SKILL.md","title":"작업 원칙","line":26,"text":"- `INSTRUCTIONS.md`에 정의된 코딩 컨벤션(명명 규칙, 주석 언어)을 절대적으로 지킵니다.\n- **한 파일은 500줄 이하**로 유지합니다. 초과 시 기능 단위로 파일을 분리합니다.\n- 하드코딩을 피하고 주요 상수는 Config 변수로 관리합니다.\n- 새 라이브러리가 필요한 경우 임의로 설치하지 않고 사용자에게 먼저 확인합니다.\n- 작업 중 생성하는 임시 파일은 `.temp data/`에 저장합니다.\n- 복잡한 패턴 선택 시 **Claude Advisor** 호출을 고려합니다 (`.agents/advisor-strategy.md` 참조).","keywords":["작업","원칙","instructions","md","정의된","코딩","컨벤션","명명","규칙","주석","언어","절대적으로","지킵니다","파일은","500","이하","유지합니다","초과","기능","단위로","파일을","분리합니다","하드코딩을","피하고"],"rank":1.0},{"id":"ce9fad2f8e4728ef","source":".agents/skills/implementer/SKILL.md","title":"작업 완료 기준","line":34,"text":"- [ ] 요청된 기능이 설계(Architect 인계 내용)에 맞게 완전히 구현되었는가?\n- [ ] Designer 디자인 명세(토큰, 컴포넌트, 에셋)가 있다면 준수했는가?\n- [ ] 코드 실행 시 문법 에러나 임포트 에러가 없는가?\n- [ ] 파일당 500줄 이하를 준수하는가?\n- [ ] 접근 제어 범위 내에서만 작업했는가? (denied_write_paths 미접근)\n- [ ] Reviewer에게 인계 포맷으로 명확히 넘겼는가?","keywords":["작업","완료","기준","요청된","기능이","설계","architect","인계","내용","맞게","완전히","구현되었는가","designer","디자인","명세","토큰","컴포넌트","에셋","있다면","준수했는가","코드","실행","문법","에러나"],"rank":1.0},{"id":"8504f4a82e14f70e","source":".agents/skills/implementer/SKILL.md","title":"⛔ 권한 자가 진단 (매 작업 전 필수 확인)","line":42,"text":"아래 조건에 하나라도 해당하면 **즉시 중단**하고 사용자에게 보고합니다:\n\n1. 내가 쓰려는 파일 경로가 `denied_write_paths`에 해당하는가? (`workspace/*`, `dist/*`, `tests/*`, `.agents/*`, `INSTRUCTIONS.md`, `GEMINI.md`)\n2. 대상 파일이 **400줄을 초과**하는가? → ABAC `large_file_alert`: Reviewer 승인 필요\n3. 대상 파일이 `**/credentials*`, `**/secrets*`, `**/.env*` 패턴에 매칭되는가? → ABAC `sensitive_data_guard`: 차단\n4. 현재 워크플로우 Step에서 Implementer 차례가 맞는가?","keywords":["권한","자가","진단","작업","필수","확인","아래","조건에","하나라도","해당하면","즉시","중단","하고","사용자에게","보고합니다","내가","쓰려는","파일","경로가","denied","write","paths","해당하는가","workspace"],"rank":1.0},{"id":"8eb14e561b4d84fc","source":".agents/skills/implementer/SKILL.md","title":"📁 스킬 리소스","line":51,"text":"- `scripts/before_tool.sh` / `scripts/before_tool.ps1` — 도구 실행 전 RBAC/ABAC 권한 체크 훅\n- `scripts/after_tool.sh` / `scripts/after_tool.ps1` — 도구 실행 후 로깅/검증 훅","keywords":["스킬","리소스","scripts","before","tool","sh","ps1","도구","실행","rbac","abac","권한","체크","after","로깅","검증"],"rank":1.0},{"id":"1e9a3efd95a52a90","source":".agents/skills/implementer/SKILL.md","title":"🤖 자동 매칭 조건 (Auto-Routing Triggers)","line":55,"text":"1. **키워드:** \"구현\", \"작성해줘\", \"만들어줘\", \"추가해줘\", \"기능\", \"로직\"\n2. **의도:** 새로운 기능을 개발하거나 기존 코드를 수정하여 핵심 비즈니스 로직을 다루려는 의도.\n3. **파일 경로:** `src/` 폴더 내 파일을 수정하거나 새로 생성할 때.\n4. **코드 패턴:** 함수/클래스 정의, 비즈니스 로직 코드가 포함될 때.","keywords":["자동","매칭","조건","auto","routing","triggers","키워드","구현","작성해줘","만들어줘","추가해줘","기능","로직","의도","새로운","기능을","개발하거나","기존","코드를","수정하여","핵심","비즈니스","로직을","다루려는"],"rank":1.0},{"id":"d4a604dc57a6f5ca","source":".agents/skills/reviewer/SKILL.md","title":"SKILL","line":1,"text":"---\nname: reviewer\ndescription: 구현된 코드의 품질, 가독성, 성능을 검토하고 500줄 제한 준수를 확인하는 에이전트. 코드가 새로 작성되거나 수정된 후 활성화된다.\ncontext: fork\nallowed_tools: [view_file, grep_search, run_command, list_dir]\ndenied_tools: [write_to_file, replace_file_content, multi_replace_file_content, search_web, browser_subagent]\nallowed_commands: [\"lint\", \"eslint\", \"pylint\", \"flake8\", \"wc -l\", \"cat\"]\n---","keywords":["skill","name","reviewer","description","구현된","코드의","품질","가독성","성능을","검토하고","500","제한","준수를","확인하는","에이전트","코드가","새로","작성되거나","수정된","활성화된다","context","fork","allowed","tools"],"rank":1.0},{"id":"28ec6e177b198a3b","source":".agents/skills/reviewer/SKILL.md","title":"역할","line":11,"text":"Implementer가 작성한 코드를 깐깐하게 검토하고 품질과 성능을 최적화합니다.\n`/setup-from-application` 워크플로우 실행 후 이 파일이 프로젝트에 맞게 자동 업데이트됩니다.\n\n> **`context: fork`** — 이 스킬은 격리된 서브에이전트에서 실행됩니다. 리뷰 결과만 요약하여 메인 대화로 반환합니다.","keywords":["역할","implementer","작성한","코드를","깐깐하게","검토하고","품질과","성능을","최적화합니다","setup","application","워크플로우","실행","파일이","프로젝트에","맞게","자동","업데이트됩니다","context","fork","스킬은","격리된","서브에이전트에서","실행됩니다"],"rank":1.0},{"id":"adce3b6af18aad37","source":".agents/skills/reviewer/SKILL.md","title":"접근 제어 (RBAC)","line":17,"text":"- **파일 읽기:** ✅ 전체\n- **파일 쓰기:** ❌ (코멘트만, 코드 수정 불가)\n- **터미널:** ✅ (린트/분석 도구만)\n- **브라우저:** ❌\n- **`workspace/`, `dist/` 쓰기:** ❌\n\n> 상세 정책 및 ABAC 동적 권한: `.agents/access-control.md` 참조","keywords":["접근","제어","rbac","파일","읽기","전체","쓰기","코멘트만","코드","수정","불가","터미널","린트","분석","도구만","브라우저","workspace","dist","상세","정책","abac","동적","권한","agents"],"rank":1.0},{"id":"e3edb86490a106d5","source":".agents/skills/reviewer/SKILL.md","title":"집중 검토 사항","line":26,"text":"- **500줄 제한:** 모든 파일의 줄 수를 확인합니다. 500줄 초과 파일이 있으면 Implementer에게 분리를 요청합니다.\n- **메모리 최적화:** 반복 실행 구조에서 메모리 누수 가능성을 점검합니다.\n- **가독성:** 단일 책임 원칙(SRP) 준수 여부, 주석 규칙 준수 여부를 검토합니다.\n- **의존성:** 라이브러리 버전 충돌 또는 deprecated API 사용 여부를 확인합니다.\n- **하드코딩:** 매직 넘버나 하드코딩된 값이 없는지 확인합니다.\n- **접근 제어 준수:** Implementer가 RBAC/ABAC 범위 내에서만 작업했는지 확인합니다.\n- **🔄 디자인 명세 일치:** UI 관련 코드가 Designer의 디자인 토큰·컴포넌트 명세와 일치하는지 확인합니다. 불일치 시 코드 문제이면 Implementer에게 반려, 명세 문제이면 Designer에게 디자인 반려합니다.","keywords":["집중","검토","사항","500","제한","모든","파일의","수를","확인합니다","초과","파일이","있으면","implementer","에게","분리를","요청합니다","메모리","최적화","반복","실행","구조에서","누수","가능성을","점검합니다"],"rank":1.0},{"id":"cb73c1fee1f855fd","source":".agents/skills/reviewer/SKILL.md","title":"작업 완료 기준","line":35,"text":"- [ ] 모든 파일이 500줄 이하인가? (초과 시 분리 요청)\n- [ ] 메모리 누수 및 리소스 미반환 가능성을 차단했는가?\n- [ ] 코딩 컨벤션(명명 규칙, 주석 언어)을 준수하는가?\n- [ ] UI 관련 코드가 디자인 명세(토큰, 컴포넌트, 에셋)와 일치하는가?\n- [ ] 잠재적 성능 이슈에 대해 Advisor 호출이 필요한가? (필요 시 `.agents/advisor-strategy.md` 참조)\n- [ ] 리뷰 결과를 인계 포맷으로 Tester에게 전달했는가?","keywords":["작업","완료","기준","모든","파일이","500","이하인가","초과","분리","요청","메모리","누수","리소스","미반환","가능성을","차단했는가","코딩","컨벤션","명명","규칙","주석","언어","준수하는가","ui"],"rank":1.0},{"id":"e9e7712d762b4afb","source":".agents/skills/reviewer/SKILL.md","title":"⛔ 권한 자가 진단 (매 작업 전 필수 확인)","line":43,"text":"아래 조건에 하나라도 해당하면 **즉시 중단**하고 사용자에게 보고합니다:\n\n1. 파일을 **쓰거나 수정**하려 하고 있는가? → Reviewer는 쓰기 권한 없음 (코멘트만 가능)\n2. 터미널에서 `allowed_commands` 외 명령을 실행하려 하는가? → lint/분석 도구만 허용\n3. Implementer가 `denied_write_paths`에 접근한 흔적이 있는가? → 접근 제어 위반 보고","keywords":["권한","자가","진단","작업","필수","확인","아래","조건에","하나라도","해당하면","즉시","중단","하고","사용자에게","보고합니다","파일을","쓰거나","수정","하려","있는가","reviewer","쓰기","없음","코멘트만"],"rank":1.0},{"id":"a9134041d6be4bab","source":".agents/skills/reviewer/SKILL.md","title":"📁 스킬 리소스","line":51,"text":"- `references/checklist.md` — 코드 리뷰 체크리스트 (프로젝트 셋팅 시 자동 커스터마이징)","keywords":["스킬","리소스","references","checklist","md","코드","리뷰","체크리스트","프로젝트","셋팅","자동","커스터마이징"],"rank":1.0},{"id":"0246d5f87bb4f3c6","source":".agents/skills/reviewer/SKILL.md","title":"🤖 자동 매칭 조건 (Auto-Routing Triggers)","line":54,"text":"1. **키워드:** \"리뷰\", \"검토해줘\", \"최적화\", \"리팩토링\", \"메모리 누수\", \"성능\", \"코드 품질\"\n2. **의도:** 작성된 코드의 성능 및 품질을 평가하거나 리팩토링을 요구하는 의도.\n3. **파일 경로:** 새롭게 작성되거나 방금 수정된 파일이 있을 때.\n4. **코드 패턴:** 반복문, 대용량 데이터 처리, 파일 입출력 코드가 포함될 때.","keywords":["자동","매칭","조건","auto","routing","triggers","키워드","리뷰","검토해줘","최적화","리팩토링","메모리","누수","성능","코드","품질","의도","작성된","코드의","품질을","평가하거나","리팩토링을","요구하는","파일"],"rank":1.0},{"id":"7174b340112e6249","source":".agents/skills/security/SKILL.md","title":"SKILL","line":1,"text":"---\nname: security\ndescription: 데이터 경계와 배포 산출물을 검증하는 에이전트\nallowed_tools: [view_file, run_command, grep_search, list_dir]\nallowed_write_paths: [\"docs/log.md\"]\ndenied_write_paths: [\"workspace/*\"]\n---","keywords":["skill","name","security","description","데이터","경계와","배포","산출물을","검증하는","에이전트","allowed","tools","view","file","run","command","grep","search","list","dir","write","paths","docs","log"],"rank":1.0},{"id":"3ef27f76ee7a20a8","source":".agents/skills/security/SKILL.md","title":"Security","line":9,"text":"테스트 통과 후 비밀·사용자 데이터·캐시가 Git과 배포 ZIP에 없는지 확인합니다.\n\n- `.env`, 키, 토큰, 파일 내용, 개인화 원문을 배포하지 않습니다.\n- `workspace/`, `.vas_backups/`, 캐시, 테스트 결과를 제외합니다.\n- `scripts/build_release.py`가 만든 manifest와 SHA-256을 검증합니다.\n- 검증 결과만 `docs/log.md`에 기록합니다.","keywords":["security","테스트","통과","비밀","사용자","데이터","캐시가","git","배포","zip","없는지","확인합니다","env","토큰","파일","내용","개인화","원문을","배포하지","않습니다","workspace","vas","backups","캐시"],"rank":1.0},{"id":"4c86fcbea9c654bd","source":".agents/skills/tester/SKILL.md","title":"SKILL","line":1,"text":"---\nname: tester\ndescription: 작성된 코드의 안정성을 검증하기 위해 테스트 코드를 작성하고 실행하는 에이전트. 코드 리뷰 통과 후 테스트가 필요할 때 활성화된다.\ncontext: fork\nallowed_tools: [view_file, write_to_file, replace_file_content, multi_replace_file_content, run_command, grep_search, list_dir]\ndenied_tools: [search_web, browser_subagent]\nallowed_write_paths: [\"tests/*\", \".temp data/*\"]\ndenied_write_paths: [\"src/*\", \"workspace/*\", \"dist/*\", \".agents/*\"]\nallowed_commands: [\"pytest\", \"jest\", \"npm test\", \"coverage\", \"python -m pytest\"]\n---","keywords":["skill","name","tester","description","작성된","코드의","안정성을","검증하기","위해","테스트","코드를","작성하고","실행하는","에이전트","코드","리뷰","통과","테스트가","필요할","활성화된다","context","fork","allowed","tools"],"rank":1.0},{"id":"54f8f2330407682c","source":".agents/skills/tester/SKILL.md","title":"역할","line":13,"text":"작성된 코드가 어떠한 돌발 상황에서도 멈추지 않도록 테스트 코드를 작성하고 검증합니다.\n`/setup-from-application` 워크플로우 실행 후 이 파일이 프로젝트에 맞게 자동 업데이트됩니다.\n\n> **`context: fork`** — 이 스킬은 격리된 서브에이전트에서 실행됩니다. 테스트 결과만 요약하여 메인 대화로 반환합니다.","keywords":["역할","작성된","코드가","어떠한","돌발","상황에서도","멈추지","않도록","테스트","코드를","작성하고","검증합니다","setup","application","워크플로우","실행","파일이","프로젝트에","맞게","자동","업데이트됩니다","context","fork","스킬은"],"rank":1.0},{"id":"ddb98f1723ce7952","source":".agents/skills/tester/SKILL.md","title":"접근 제어 (RBAC)","line":19,"text":"- **파일 읽기:** ✅ 전체\n- **파일 쓰기:** ✅ `tests/`, `.temp data/` (테스트 코드만)\n- **터미널:** ✅ (테스트 실행만)\n- **브라우저:** ❌\n- **`workspace/`, `dist/` 쓰기:** ❌\n- **소스 코드 수정:** ❌ (테스트 실패 시 Implementer에게 인계)\n\n> 상세 정책 및 ABAC 동적 권한: `.agents/access-control.md` 참조","keywords":["접근","제어","rbac","파일","읽기","전체","쓰기","tests","temp","data","테스트","코드만","터미널","실행만","브라우저","workspace","dist","소스","코드","수정","실패","implementer","에게","인계"],"rank":1.0},{"id":"0917579b6e9fd751","source":".agents/skills/tester/SKILL.md","title":"필수 테스트 케이스 (Edge Cases)","line":29,"text":"- [ ] 외부 입력(파일, API 응답, 사용자 입력 등) 오류 발생 시 예외 처리가 올바르게 동작하는가?\n- [ ] 노이즈, 빈 값, 쓰레기 값 등 비정상 데이터 입력 시 크래시 없이 처리되는가?\n- [ ] 잘못된 타입/형식의 데이터가 들어왔을 때 안전하게 무시하거나 오류를 반환하는가?\n- [ ] 정상 동작하는 기본 케이스(Happy Path)가 모두 통과하는가?","keywords":["필수","테스트","케이스","edge","cases","외부","입력","파일","api","응답","사용자","오류","발생","예외","처리가","올바르게","동작하는가","노이즈","쓰레기","비정상","데이터","크래시","없이","처리되는가"],"rank":1.0},{"id":"8babedd254877d80","source":".agents/skills/tester/SKILL.md","title":"작업 완료 기준","line":35,"text":"- [ ] 테스트 커버리지 목표(기본 80% 이상)를 달성했는가?\n- [ ] 모든 테스트가 통과하는가?\n- [ ] 놓친 엣지 케이스에 대해 Advisor 호출이 필요한가? (필요 시 `.agents/advisor-strategy.md` 참조)\n- [ ] 통과하지 못한 테스트가 있다면 Implementer에게 재인계했는가?\n- [ ] Security 에이전트에게 인계 포맷으로 결과를 전달했는가?","keywords":["작업","완료","기준","테스트","커버리지","목표","기본","80","이상","달성했는가","모든","테스트가","통과하는가","놓친","엣지","케이스에","대해","advisor","호출이","필요한가","필요","agents","strategy","md"],"rank":1.0},{"id":"c71dca344f4ada32","source":".agents/skills/tester/SKILL.md","title":"⛔ 권한 자가 진단 (매 작업 전 필수 확인)","line":42,"text":"아래 조건에 하나라도 해당하면 **즉시 중단**하고 사용자에게 보고합니다:\n\n1. `src/*`, `workspace/*`, `dist/*` 파일을 **수정**하려 하고 있는가? → Tester는 `tests/`, `.temp data/`만 쓰기 가능\n2. 터미널에서 `allowed_commands` 외 명령을 실행하려 하는가? → 테스트 실행 도구만 허용\n3. 테스트 실패 시 소스 코드를 직접 고치려 하고 있는가? → Implementer에게 인계 필요","keywords":["권한","자가","진단","작업","필수","확인","아래","조건에","하나라도","해당하면","즉시","중단","하고","사용자에게","보고합니다","src","workspace","dist","파일을","수정","하려","있는가","tester","tests"],"rank":1.0},{"id":"acb843c78a2cb1d2","source":".agents/skills/tester/SKILL.md","title":"📁 스킬 리소스","line":50,"text":"- `scripts/run_tests.sh` / `scripts/run_tests.ps1` — 테스트 러너 스크립트 (프로젝트 셋팅 시 자동 커스터마이징)","keywords":["스킬","리소스","scripts","run","tests","sh","ps1","테스트","러너","스크립트","프로젝트","셋팅","자동","커스터마이징"],"rank":1.0},{"id":"92512188e0af3626","source":".agents/skills/tester/SKILL.md","title":"🤖 자동 매칭 조건 (Auto-Routing Triggers)","line":53,"text":"1. **키워드:** \"테스트\", \"검증\", \"방어\", \"예외 처리\", \"엣지 케이스\", \"커버리지\"\n2. **의도:** 코드가 예기치 못한 상황에서도 안전한지 테스트 코드를 작성하려는 의도.\n3. **파일 경로:** `tests/` 폴더 내부 또는 `test_*.py` / `*.test.js` 파일 작성 중일 때.\n4. **코드 패턴:** `import pytest`, `describe(`, `assert`, `expect(` 등 테스트 코드 패턴이 포함될 때.","keywords":["자동","매칭","조건","auto","routing","triggers","키워드","테스트","검증","방어","예외","처리","엣지","케이스","커버리지","의도","코드가","예기치","못한","상황에서도","안전한지","코드를","작성하려는","파일"],"rank":1.0},{"id":"ab9d9f87b395be38","source":".agents/workflows/CUSTOM_GUIDE.md","title":"커스텀 워크플로우 작성 가이드","line":1,"text":"프로젝트 고유의 워크플로우(예: `/deploy`, `/refactor`, `/data-pipeline`)를 만들 때 이 가이드를 참고합니다.\n\n---","keywords":["커스텀","워크플로우","작성","가이드","프로젝트","고유의","deploy","refactor","data","pipeline","만들","가이드를","참고합니다"],"rank":1.0},{"id":"80e7788786b961e7","source":".agents/workflows/CUSTOM_GUIDE.md","title":"워크플로우 파일 구조","line":7,"text":"```yaml\n---\ndescription: 한 줄로 워크플로우 목적 설명\n---\n```\n\n```markdown\n# 워크플로우: [이름] (/슬래시-커맨드)\n\n[목적 설명 1~2줄]\n\n## 실행 조건\n- [언제 이 워크플로우를 사용하는지]\n\n---\n\n## Step 1. [단계명]\n\n**담당:** [에이전트명]\n\n> **진입 조건:** [이 Step에 들어오기 위한 전제 조건]\n\n1. [할 일]\n2. [할 일]\n\n---\n\n## Step N. 완료 보고\n\n`docs/log.md`에 이력을 기록한다.\n`GEMINI.md`의 \"현재 진행 상태\"를 업데이트한다.\n```\n\n---","keywords":["워크플로우","파일","구조","yaml","description","줄로","목적","설명","markdown","이름","슬래시","커맨드","실행","조건","언제","워크플로우를","사용하는지","step","단계명","담당","에이전트명","진입","들어오기","위한"],"rank":1.0},{"id":"6ee4e67288090cba","source":".agents/workflows/CUSTOM_GUIDE.md","title":"필수 포함 요소 체크리스트","line":44,"text":"| 요소 | 필수 | 설명 |\n|------|:----:|------|\n| YAML 프론트매터 `description` | ✅ | 슬래시 커맨드 목록에 표시됨 |\n| 실행 조건 | ✅ | 언제 이 워크플로우를 쓰는지 |\n| 각 Step별 담당 에이전트 | ✅ | SKILL.md 경로 포함 |\n| 각 Step별 진입 조건 | ✅ | 중단 복구 시 판단 기준 |\n| 각 Step별 RBAC/ABAC 명시 | ✅ | 권한 범위 명확화 |\n| 인계 포맷 | ✅ | 표준 인계 포맷 사용 |\n| 반복 제한 + 에스컬레이션 | ✅ | 무한 루프 방지 |\n| docs/log.md 업데이트 | ✅ | 마지막 Step에서 |\n| GEMINI.md 상태 업데이트 | ✅ | 시작/종료 시 |\n\n---","keywords":["필수","포함","요소","체크리스트","설명","yaml","프론트매터","description","슬래시","커맨드","목록에","표시됨","실행","조건","언제","워크플로우를","쓰는지","step","담당","에이전트","skill","md","경로","진입"],"rank":1.0},{"id":"2bd028c86a23a0d2","source":".agents/workflows/CUSTOM_GUIDE.md","title":"네이밍 규칙","line":60,"text":"- 파일명: `kebab-case.md` (예: `dep-update.md`, `data-pipeline.md`)\n- 슬래시 커맨드: `/kebab-case` (예: `/dep-update`)\n- Step 번호: 0부터 시작 (사전 판단 필요 시) 또는 1부터 시작\n\n---","keywords":["네이밍","규칙","파일명","kebab","case","md","dep","update","data","pipeline","슬래시","커맨드","step","번호","부터","시작","사전","판단","필요","또는"],"rank":1.0},{"id":"1a2c74eed01ee0ed","source":".agents/workflows/CUSTOM_GUIDE.md","title":"등록 방법","line":68,"text":"1. `.agents/workflows/` 디렉터리에 `.md` 파일 생성\n2. YAML 프론트매터에 `description` 포함\n3. 에이전트 시스템이 자동으로 슬래시 커맨드로 인식\n\n> 별도 설정 파일 수정 없이, 파일 생성만으로 등록됩니다.","keywords":["등록","방법","agents","workflows","디렉터리에","md","파일","생성","yaml","프론트매터에","description","포함","에이전트","시스템이","자동으로","슬래시","커맨드로","인식","별도","설정","수정","없이","생성만으로","등록됩니다"],"rank":1.0},{"id":"46adf4bdaa2a752a","source":".agents/workflows/dep-update.md","title":"/dep-update","line":1,"text":"1. 변경 이유와 호환 범위를 확인합니다.\n2. 사용자 승인 후 잠금 파일과 선언 파일만 갱신합니다.\n3. 단일 Python·브라우저 테스트를 실행합니다.\n4. 라이선스·취약점·배포 포함 여부를 확인합니다.\n5. 필요하면 `scripts/build_release.py`로 새 배포물을 검증합니다.\n\n사용자 프로젝트의 의존성은 해당 `workspace/projects/<name>/` 내부에서 별도로 관리합니다.","keywords":["dep","update","변경","이유와","호환","범위를","확인합니다","사용자","승인","잠금","파일과","선언","파일만","갱신합니다","단일","python","브라우저","테스트를","실행합니다","라이선스","취약점","배포","포함","여부를"],"rank":1.0},{"id":"f85d43452d1312b0","source":".agents/workflows/dev-cycle.md","title":"/dev-cycle","line":1,"text":"1. Architect: 목적·인터페이스·검증 기준 정의\n2. Designer: UI 변경이 있으면 상태·접근성·반응형 명세\n3. Implementer: `src/` 또는 `scripts/`에 최소 변경\n4. Reviewer: 회귀·데이터 경계·500줄 점검\n5. Tester: 관련 단일 테스트와 브라우저 흐름 검증\n6. Security: 비밀·사용자 데이터 제외 확인 후 릴리즈 생성\n7. `docs/log.md`에 결과 기록\n\n새 사용자 프로그램은 `workspace/projects/<name>/`, VAS 자체 변경은 코어 원본에 둡니다.","keywords":["dev","cycle","architect","목적","인터페이스","검증","기준","정의","designer","ui","변경이","있으면","상태","접근성","반응형","명세","implementer","src","또는","scripts","최소","변경","reviewer","회귀"],"rank":1.0},{"id":"916d269d90fbdc3f","source":".agents/workflows/hotfix.md","title":"/hotfix","line":1,"text":"1. 재현 조건과 영향 범위를 고정합니다.\n2. 가장 작은 수정과 회귀 테스트를 함께 추가합니다.\n3. 관련 Python·브라우저 테스트를 실행합니다.\n4. 비밀·사용자 데이터·생성물이 Git에 없는지 확인합니다.\n5. 필요할 때만 릴리즈를 다시 생성합니다.\n\n긴급 수정도 기존 프로젝트 원본 보호와 동의 기반 개인화 규칙을 우회하지 않습니다.","keywords":["hotfix","재현","조건과","영향","범위를","고정합니다","가장","작은","수정과","회귀","테스트를","함께","추가합니다","관련","python","브라우저","실행합니다","비밀","사용자","데이터","생성물이","git","없는지","확인합니다"],"rank":1.0},{"id":"c79f3071a9568ae6","source":".agents/workflows/migration-cycle.md","title":"/migration-cycle","line":1,"text":"기존 프로그램을 VAS에 안전하게 연결하는 흐름입니다.\n\n1. 사용자가 원래 프로젝트 폴더를 선택합니다.\n2. Architect가 읽기 전용으로 구조·스택·Git·위험 요소를 분석합니다.\n3. 사용자에게 분석 보고서와 복제 옵션을 보여주고 승인을 받습니다.\n4. 체크포인트, SHA-256 목록, 가능한 Git bundle을 만듭니다.\n5. staging으로 복제하고 링크 이탈·해시·대상 충돌을 검사합니다.\n6. `workspace/projects/<name>/`으로 원자적으로 승격합니다.\n7. 프로젝트 목록과 선택적 RAG 색인을 갱신합니다.\n8. 단일 테스트를 실행하고 되돌리기 ID를 제공합니다.\n\n원본 실행·수정·삭제는 기본 흐름에서 금지합니다. 원본 삭제는 별도 고급 명령과 정확한 확인 문구가 있어야 합니다.","keywords":["migration","cycle","기존","프로그램을","vas","안전하게","연결하는","흐름입니다","사용자가","원래","프로젝트","폴더를","선택합니다","architect","읽기","전용으로","구조","스택","git","위험","요소를","분석합니다","사용자에게","분석"],"rank":1.0},{"id":"d01e9efbec09338a","source":".agents/workflows/setup-from-application.md","title":"/setup-from-application","line":1,"text":"1. 신청서 JSON의 스키마와 필수값을 검증합니다.\n2. 프로젝트 이름을 안전한 폴더명으로 정규화합니다.\n3. `workspace/projects/<name>/`에 새 프로젝트를 만듭니다.\n4. 요구사항, 선택한 테마 상태, 작업 체크리스트를 프로젝트 내부 문서로 저장합니다.\n5. 프로젝트 레지스트리와 선택적 지식 색인을 갱신합니다.\n6. 생성 결과와 다음 작업 링크를 허브에 표시합니다.\n\n신청서 첨부 파일은 이름·크기·형식 메타데이터만 다루며 파일 내용은 자동 업로드하지 않습니다.","keywords":["setup","application","신청서","json","스키마와","필수값을","검증합니다","프로젝트","이름을","안전한","폴더명으로","정규화합니다","workspace","projects","name","프로젝트를","만듭니다","요구사항","선택한","테마","상태","작업","체크리스트를","내부"],"rank":1.0},{"id":"7ef97fa0f87824fa","source":".agents/workflows/ultra-plan.md","title":"ultra plan","line":1,"text":"---\ndescription: 복잡한 설계 시 3+1 병렬 탐색-비평 패턴으로 최적 아키텍처를 도출한다\n---","keywords":["ultra","plan","description","복잡한","설계","병렬","탐색","비평","패턴으로","최적","아키텍처를","도출한다"],"rank":1.0},{"id":"69e8aa36be4b7582","source":".agents/workflows/ultra-plan.md","title":"워크플로우: 울트라 플랜 (Ultra Plan)","line":5,"text":"단일 Architect의 **앵커링 문제**(첫 판단에 갇히는 문제)를 해결하기 위해,\n**3개의 독립 탐색 + 1개의 비평**으로 최적 설계안을 도출합니다.","keywords":["워크플로우","울트라","플랜","ultra","plan","단일","architect","앵커링","문제","판단에","갇히는","해결하기","위해","개의","독립","탐색","비평","최적","설계안을","도출합니다"],"rank":1.0},{"id":"257f782e859c118c","source":".agents/workflows/ultra-plan.md","title":"실행 조건","line":10,"text":"- `/dev-cycle` Step 0에서 복잡도 기준 해당 시 자동 진입\n- 또는 `/ultra-plan` 슬래시 커맨드를 직접 입력했을 때","keywords":["실행","조건","dev","cycle","step","복잡도","기준","해당","자동","진입","또는","ultra","plan","슬래시","커맨드를","직접","입력했을"],"rank":1.0},{"id":"bb041f27ee08ccc5","source":".agents/workflows/ultra-plan.md","title":"울트라 플랜 진입 기준","line":14,"text":"| 기준 | 예시 |\n|------|------|\n| 신규 시스템 아키텍처 설계 | \"마이크로서비스로 전환해줘\" |\n| 파일 10개 이상 동시 변경 | \"인증 시스템 전면 교체\" |\n| 기술 스택 변경/마이그레이션 | \"Django → FastAPI 마이그레이션\" |\n| 성능 최적화 (다수 접근법 가능) | \"응답 속도 50% 개선\" |\n| 사용자 명시적 요청 | `/ultra-plan` 커맨드 |\n\n---","keywords":["울트라","플랜","진입","기준","예시","신규","시스템","아키텍처","설계","마이크로서비스로","전환해줘","파일","10","이상","동시","변경","인증","전면","교체","기술","스택","마이그레이션","django","fastapi"],"rank":1.0},{"id":"6475439ef8788df2","source":".agents/workflows/ultra-plan.md","title":"Step 1. 복잡도 판단","line":26,"text":"**담당:** Architect\n\n1. 사용자 요청을 분석하여 위 진입 기준에 해당하는지 판단한다.\n2. 해당하지 않으면 일반 `/dev-cycle` Step 1로 전환한다.\n3. 해당하면 아래 탐색 프레임워크를 설정한다:\n   - 탐색 관점 3가지를 정의 (예: 성능 우선 / 유지보수 우선 / 비용 최적)\n4. `GEMINI.md`의 \"현재 진행 상태\"를 업데이트한다: `활성 워크플로우: /ultra-plan Step 1`\n\n```\n[울트라 플랜 진입]\n- 요청: [사용자 요청 요약]\n- 판단 근거: [진입 기준 해당 항목]\n- 탐색 관점:\n  A: [관점 1 설명]\n  B: [관점 2 설명]\n  C: [관점 3 설명]\n```\n\n---","keywords":["step","복잡도","판단","담당","architect","사용자","요청을","분석하여","진입","기준에","해당하는지","판단한다","해당하지","않으면","일반","dev","cycle","전환한다","해당하면","아래","탐색","프레임워크를","설정한다","관점"],"rank":1.0},{"id":"0e7969c8a8d1c6a4","source":".agents/workflows/ultra-plan.md","title":"Step 2. 독립 탐색 (3개 관점)","line":48,"text":"**담당:** 탐색자 A, B, C (Architect가 순차적으로 3가지 관점을 시뮬레이션)\n\n> **핵심 규칙:** 각 탐색은 **완전히 독립적**으로 수행합니다.\n> 다른 탐색의 결과를 참조하거나 영향받아서는 안 됩니다.\n> 스킬 2.0의 `context: fork`가 지원되면 각각 격리된 서브에이전트에서 실행합니다.\n>\n> **진입 조건:** Step 1에서 탐색 관점 3가지가 정의됨\n\n각 탐색자는 아래를 포함한 설계안을 작성합니다:\n\n1. **아키텍처 개요** — 전체 구조와 핵심 설계 결정\n2. **파일/모듈 구조** — 디렉터리 트리와 각 파일의 역할\n3. **주요 인터페이스** — 핵심 함수/클래스의 시그니처\n4. **장점** — 이 접근법의 강점 3가지\n5. **리스크** — 예상되는 약점 또는 기술 부채\n\n---","keywords":["step","독립","탐색","관점","담당","탐색자","architect","순차적으로","가지","관점을","시뮬레이션","핵심","규칙","탐색은","완전히","독립적","수행합니다","다른","탐색의","결과를","참조하거나","영향받아서는","됩니다","스킬"],"rank":1.0},{"id":"f831834e0003a40b","source":".agents/workflows/ultra-plan.md","title":"Step 3. 비평 (Critic)","line":68,"text":"**담당:** Critic (별도 관점에서 3개 설계를 비교 분석)\n\n> **진입 조건:** 3개 탐색 설계안이 모두 완료됨\n\n1. 3개 설계안을 아래 기준으로 비교 분석한다:\n\n| 비교 항목 | 설명 |\n|----------|------|\n| 기능 완전성 | 요청된 기능이 모두 구현 가능한가? |\n| 확장성 | 향후 기능 추가에 유연한가? |\n| 복잡도 | 구현 난이도와 유지보수 비용은? |\n| 성능 | 예상 성능 병목은? |\n| 보안 | 보안 위험 요소는? |\n| 기술 부채 | 장기적으로 쌓일 수 있는 기술 부채는? |\n\n2. 비교 결과를 표로 정리한다.\n3. 최적 접근법 또는 접근법 조합을 추천한다.\n\n```\n[비평 결과]\n- 추천: [탐색 A/B/C 또는 조합]\n- 근거: [핵심 이유 3가지]\n- 보완 필요: [추천안에서 보강해야 할 부분]\n```\n\n---","keywords":["step","비평","critic","담당","별도","관점에서","설계를","비교","분석","진입","조건","탐색","설계안이","모두","완료됨","설계안을","아래","기준으로","분석한다","항목","설명","기능","완전성","요청된"],"rank":1.0},{"id":"776185974cd01273","source":".agents/workflows/ultra-plan.md","title":"Step 4. 최적 설계안 합성","line":97,"text":"**담당:** Architect\n\n> **진입 조건:** Critic 비평 결과 완료 + 추천안 제시됨\n\n1. Critic의 비평 결과를 바탕으로 최적 설계안 1개를 확정한다.\n2. 필요 시 여러 탐색의 장점을 조합하여 하이브리드 설계안을 작성한다.\n3. 최종 설계안을 아래 형식으로 사용자에게 제시한다.\n\n```\n[최종 설계안]\n- 채택 근거: [탐색 A/B/C 중 채택 또는 하이브리드 근거]\n- 아키텍처 개요: [전체 구조]\n- 파일/모듈 구조: [디렉터리 트리]\n- 주요 인터페이스: [함수/클래스 시그니처]\n- 예상 작업량: [파일 수, 예상 시간]\n- 리스크 대응: [Critic이 지적한 약점에 대한 대응]\n```\n\n---","keywords":["step","최적","설계안","합성","담당","architect","진입","조건","critic","비평","결과","완료","추천안","제시됨","결과를","바탕으로","개를","확정한다","필요","여러","탐색의","장점을","조합하여","하이브리드"],"rank":1.0},{"id":"1883a3efc24a3df7","source":".agents/workflows/ultra-plan.md","title":"Step 5. 사용자 승인","line":119,"text":"설계안을 사용자에게 보여주고 승인을 받습니다.\n사용자가 수정을 요청하면 Step 4를 반복합니다.\n\n---","keywords":["step","사용자","승인","설계안을","사용자에게","보여주고","승인을","받습니다","사용자가","수정을","요청하면","반복합니다"],"rank":1.0},{"id":"b063dc77e923158b","source":".agents/workflows/ultra-plan.md","title":"Step 6. 실행 → dev-cycle 연결","line":126,"text":"승인된 설계안을 기반으로 일반 `/dev-cycle`로 진행합니다.\n- **UI 디자인이 필요한 경우:** Step 1.5(Designer 디자인)부터 시작\n- **UI 디자인이 불필요한 경우:** Step 2(Implementer 구현)부터 시작\n\n```\n[인계] Architect (울트라 플랜) → Designer 또는 Implementer\n- 완료: 울트라 플랜 최종 설계안 확정\n- UI 디자인 필요: [예 → Designer로 / 아니오 → Implementer로]\n- 구현 대상 파일: [파일 목록]\n- 주요 인터페이스: [함수/클래스 시그니처 요약]\n- [Advisor 참조] [사용 시 질문/답변 요약 / 미사용 시 생략]\n- 특이사항: [3개 탐색에서 공통 지적된 리스크]\n```\n\n`GEMINI.md`의 \"현재 진행 상태\"를 업데이트한다: `활성 워크플로우: /dev-cycle Step 1.5 또는 2 (울트라 플랜 경유)`\n설계 과정에서 주목할 교훈(탐색 간 갈등, 비평 핵심 지적 등)이 있으면 `docs/log.md`에 기록한다.","keywords":["step","실행","dev","cycle","연결","승인된","설계안을","기반으로","일반","진행합니다","ui","디자인이","필요한","경우","designer","디자인","부터","시작","불필요한","implementer","구현","인계","architect","울트라"],"rank":1.0},{"id":"f7b8044bac468d8b","source":"docs/clean-copy-package-plan.md","title":"배포 패키지 기준","line":1,"text":"`python scripts/build_release.py`가 `dist/`에 아래 결과를 만듭니다.\n\n- `VAS-2.6.2-windows.zip`: 로컬 서버·가져오기·개인화 포함 전체 실행본\n- `VAS-Client-Form-2.6.2.zip`: 외부 공유용 독립 신청서\n- `pages/`: GitHub Pages용 정적 허브\n- `release-manifest.json`, `SHA256SUMS.txt`: 파일 목록과 검증 해시\n\n`.git`, `workspace`, `dist`, 백업, 캐시, 테스트 결과, 환경 변수, 키 파일은 제외됩니다. 실행 시 필요한 `workspace/`는 로컬 런타임이 새로 만듭니다.","keywords":["배포","패키지","기준","python","scripts","build","release","py","dist","아래","결과를","만듭니다","vas","windows","zip","로컬","서버","가져오기","개인화","포함","전체","실행본","client","form"],"rank":1.0},{"id":"1d3d7110ea0d2aac","source":"docs/design-studio-controls.md","title":"디자인 스튜디오 사용 흐름","line":1,"text":"VAS 디자인 스튜디오는 프리셋을 고르고, 필요한 경우 Taste Profile을 조정한 뒤, 에이전트용 prompt와 디자인 토큰을 내보내는 내부 작업자용 도구입니다.","keywords":["디자인","스튜디오","사용","흐름","vas","스튜디오는","프리셋을","고르고","필요한","경우","taste","profile","조정한","에이전트용","prompt","토큰을","내보내는","내부","작업자용","도구입니다"],"rank":1.0},{"id":"8a17713187c6d856","source":"docs/design-studio-controls.md","title":"진입점","line":5,"text":"- 브라우저에서 `src/design-controller.html`을 엽니다.\n- 일반 사용자는 `Run-VAS-System.bat` 또는 `src/vas-hub.html`에서 디자인 스튜디오로 들어갈 수 있습니다.","keywords":["진입점","브라우저에서","src","design","controller","html","엽니다","일반","사용자는","run","vas","system","bat","또는","hub","디자인","스튜디오로","들어갈","있습니다"],"rank":1.0},{"id":"0f95f29fa32ceb28","source":"docs/design-studio-controls.md","title":"기본 흐름","line":10,"text":"1. 프리셋을 선택합니다.\n2. `Taste Profile`은 기본값인 `프리셋 기준 자동`으로 둡니다.\n3. `AI 에이전트 시스템 프롬프트`를 확인하고 복사합니다.\n4. 필요하면 색상, 폰트, 여백, 둥글기, 테두리, 그림자를 조정합니다.\n5. `포맷 추출 (JSON/CSS)` 또는 `토큰 다운로드`로 토큰을 내보냅니다.\n\n새 환경의 기본 조합은 `awwwards / Editorial Motion`입니다. 사용자가 다른 프리셋이나 토큰을 고르면 그 선택이 우선합니다.","keywords":["기본","흐름","프리셋을","선택합니다","taste","profile","기본값인","프리셋","기준","자동","둡니다","ai","에이전트","시스템","프롬프트","확인하고","복사합니다","필요하면","색상","폰트","여백","둥글기","테두리","그림자를"],"rank":1.0},{"id":"9f077161a58d0d91","source":"docs/design-studio-controls.md","title":"프리셋","line":20,"text":"프리셋은 전체 디자인 방향을 한 번에 정합니다.\n\n- 색상, 폰트, 반경, 여백, 그림자 같은 preview token을 반영합니다.\n- Agent Prompt의 `[PRESET DIRECTION]`에 프리셋 의도를 넣습니다.\n- 자동 모드에서는 프리셋에 맞는 Taste Profile을 함께 고릅니다.","keywords":["프리셋","프리셋은","전체","디자인","방향을","번에","정합니다","색상","폰트","반경","여백","그림자","같은","preview","token","반영합니다","agent","prompt","preset","direction","의도를","넣습니다","자동","모드에서는"],"rank":1.0},{"id":"20028c33c1d51cab","source":"docs/design-studio-controls.md","title":"Taste Profile","line":28,"text":"`Taste Profile`은 prompt의 디자인 판단 성향을 정합니다. 화면 preview token 자체를 바꾸는 기능은 아닙니다.","keywords":["taste","profile","prompt","디자인","판단","성향을","정합니다","화면","preview","token","자체를","바꾸는","기능은","아닙니다"],"rank":1.0},{"id":"7b3d69354c49f678","source":"docs/design-studio-controls.md","title":"프리셋 기준 자동","line":32,"text":"- 기본값입니다.\n- 프리셋마다 정해진 profile mapping을 사용합니다.\n- 다른 프리셋을 선택하면 해당 프리셋 기준 profile로 자동 전환됩니다.","keywords":["프리셋","기준","자동","기본값입니다","프리셋마다","정해진","profile","mapping","사용합니다","다른","프리셋을","선택하면","해당","전환됩니다"],"rank":1.0},{"id":"cdf7a911735e1882","source":"docs/design-studio-controls.md","title":"수동 선택","line":38,"text":"- 특정 profile을 직접 고르면 prompt의 `Taste Profile`과 `[TASTE PROFILE RULES]`가 바뀝니다.\n- 수동 선택 상태에서 다른 프리셋을 골라도 수동 profile이 유지됩니다.\n- 다시 자동으로 돌아가려면 `Taste Profile`에서 `프리셋 기준 자동`을 선택합니다.\n- 선택값은 브라우저 `localStorage.vasTasteProfileMode`에 저장됩니다.","keywords":["수동","선택","특정","profile","직접","고르면","prompt","taste","rules","바뀝니다","상태에서","다른","프리셋을","골라도","유지됩니다","다시","자동으로","돌아가려면","프리셋","기준","자동","선택합니다","선택값은","브라우저"],"rank":1.0},{"id":"2952c21dad3fa809","source":"docs/design-studio-controls.md","title":"Agent Prompt","line":45,"text":"Agent Prompt는 에이전트에게 전달할 작업 지시문입니다. 아래 5개 섹션은 유지되어야 합니다.\n\n- `[BASELINE RULES]`\n- `[TASTE PROFILE RULES]`\n- `[PRESET DIRECTION]`\n- `[CONFLICT POLICY]`\n- `[OUTPUT CONTRACT]`","keywords":["agent","prompt","에이전트에게","전달할","작업","지시문입니다","아래","섹션은","유지되어야","baseline","rules","taste","profile","preset","direction","conflict","policy","output","contract"],"rank":1.0},{"id":"985640d96f421e81","source":"docs/design-studio-controls.md","title":"Token Export","line":55,"text":"- `JSON`: 현재 디자인 토큰을 저장하거나 다시 불러올 때 사용합니다.\n- `CSS`: CSS 변수 형태로 다른 HTML/CSS 작업에 옮길 때 사용합니다.\n- `Tailwind`: Tailwind config 형태가 필요한 경우 참고용으로 사용합니다.\n- `코드 복사`: 현재 선택된 출력 형식을 클립보드에 복사합니다.","keywords":["token","export","json","현재","디자인","토큰을","저장하거나","다시","불러올","사용합니다","css","변수","형태로","다른","html","작업에","옮길","tailwind","config","형태가","필요한","경우","참고용으로","코드"],"rank":1.0},{"id":"ffc61a416e162dd0","source":"docs/design-studio-controls.md","title":"검증 명령","line":62,"text":"```powershell\npython tests\\test_html_syntax.py\nnpm.cmd run test:browser\n```\n\n브라우저 검사는 프리셋 토큰 반영과 Taste Profile 자동/수동 전환을 함께 확인합니다.","keywords":["검증","명령","powershell","python","tests","test","html","syntax","py","npm","cmd","run","browser","브라우저","검사는","프리셋","토큰","반영과","taste","profile","자동","수동","전환을","함께"],"rank":1.0},{"id":"0c7dbc4120cf1949","source":"docs/design-system.md","title":"디자인 시스템 (Design System)","line":1,"text":"이 문서는 VAS 2.6.2 에이전트 팀이 UI/UX를 개발할 때 참조하는 **단일 진실 공급원(Single Source of Truth)**입니다.\n과거의 고정된(하드코딩된) 다크모드 룰은 폐기되었으며, 메인 디자인 시스템과 산출물 생성은 **내장 하이브리드 디자인 스튜디오**를 기준으로 합니다.\n\n---","keywords":["디자인","시스템","design","system","문서는","vas","에이전트","팀이","ui","ux","개발할","참조하는","단일","진실","공급원","single","source","of","truth","입니다","과거의","고정된","하드코딩된","다크모드"],"rank":1.0},{"id":"c72473b6e4e215bf","source":"docs/design-system.md","title":"🎨 1. 디자인 토큰 추출 원칙 (Vibecoding Core)","line":8,"text":"Implementer 및 Designer 에이전트는 코딩을 시작하기 전, **`src/design-controller.html`과 `src/design-presets.js`의 토큰/프리셋** 또는 사용자가 제공한 산출물을 기준으로 삼아야 합니다.\n\n- **비개발자 권장 흐름:** `Run-VAS-System.bat` 실행 → VAS 허브 → 디자인 스튜디오 → 프리셋/토큰 조정 → JSON/CSS/Tailwind 추출.\n- **디자인 스튜디오 위치:** `src/design-controller.html`\n- **신규 기본값:** `awwwards` 프리셋과 `Editorial Motion` Taste Profile을 사용합니다.\n- 사용자(팀 리드)가 특정 디자인 시스템, 토큰 JSON, 또는 산출물을 제공하면 해당 파일을 최상위 시각 명세로 간주합니다.\n- 임의의 보라색/형광색 템플릿(Slop) 그라디언트나 촌스러운 중앙 정렬은 원천 차단됩니다.","keywords":["디자인","토큰","추출","원칙","vibecoding","core","implementer","designer","에이전트는","코딩을","시작하기","src","design","controller","html","presets","js","프리셋","또는","사용자가","제공한","산출물을","기준으로","삼아야"],"rank":1.0},{"id":"23390dc5adba6dcc","source":"docs/design-system.md","title":"🔤 2. 공통 타이포그래피 (Typography Tokens)","line":18,"text":"프리셋 프롬프트에서 별도의 폰트를 지정하지 않은 경우, 아래 기본 룰을 따릅니다.\n\n- **기본 한글 폰트:** 운영체제 기본 sans 스택 (`system-ui`, `Segoe UI`, `Malgun Gothic`, `Apple SD Gothic Neo`)\n- **숫자 및 코드 폰트:** 시스템 mono 스택 (`ui-monospace`, `Cascadia Code`, `Consolas`)\n- **헤드라인 규칙:** 거대하게 키우지 말고 `tracking-tighter` (자간 좁게), `leading-none` (행간 좁게) 적용.\n- **이모지 규칙:** 시스템 이모지 대신 Phosphor/Radix 등 고품질 웹 아이콘 사용 원칙.","keywords":["공통","타이포그래피","typography","tokens","프리셋","프롬프트에서","별도의","폰트를","지정하지","않은","경우","아래","기본","룰을","따릅니다","한글","폰트","운영체제","sans","스택","system","ui","segoe","malgun"],"rank":1.0},{"id":"faafe0fc6adb559b","source":"docs/design-system.md","title":"🪄 3. 공통 애니메이션 및 모션 (Motion Specs)","line":27,"text":"프리셋 프롬프트에서 모션 속도(Speed)를 지정받으면 해당 속도를 기준 삼아 애니메이션을 구성합니다. 무거운 외부 라이브러리(Framer Motion 등) 없이 순수 Vanilla CSS와 JS만으로 구현합니다.\n\n- **타이밍 함수 (Timing Function):**\n  - 기본 모션: `cubic-bezier(0.16, 1, 0.3, 1)` 적용 (스프링처럼 쫀득한 움직임)\n- **택타일 피드백 (Tactile Feedback):**\n  - 모든 버튼/인터랙티브 요소는 `:active` 상태에서 `transform: scale(0.98);` 로 살짝 눌리는 물리적 피드백 제공.","keywords":["공통","애니메이션","모션","motion","specs","프리셋","프롬프트에서","속도","speed","지정받으면","해당","속도를","기준","삼아","애니메이션을","구성합니다","무거운","외부","라이브러리","framer","없이","순수","vanilla","css"],"rank":1.0},{"id":"1b5e1fba0632e100","source":"docs/design-system.md","title":"📐 4. 레이아웃과 형태 (Layout & Shapes)","line":36,"text":"- **비대칭성 (Asymmetry):** 뻔한 3단 횡렬 배치, 무조건적인 텍스트 가운데 정렬 금지.\n- **음수 공간 (Negative Space):** 빽빽한 컨테이너(Card) 남용 금지. 선(Divider)과 여백만으로 데이터를 그룹화하여 공기처럼 가벼운 레이아웃 지향.\n- **Radius 및 Border:** 프리셋에서 주어진 토큰(예: IBM Carbon의 경우 0px, Google M3의 경우 16px)을 완벽하게 따라야 합니다.","keywords":["레이아웃과","형태","layout","shapes","비대칭성","asymmetry","뻔한","횡렬","배치","무조건적인","텍스트","가운데","정렬","금지","음수","공간","negative","space","빽빽한","컨테이너","card","남용","divider","여백만으로"],"rank":1.0},{"id":"e90983c453365562","source":"docs/design-system.md","title":"5. 기본값과 호환성","line":42,"text":"- 새 저장소는 `awwwards`로 시작합니다.\n- 기존 저장소의 색상·간격·프리셋은 자동 전환하지 않습니다.\n- 허브와 연결 화면은 `VASThemeState`의 토큰을 사용하고, URL 상태 브리지로 선택값을 이어갑니다.","keywords":["기본값과","호환성","저장소는","awwwards","시작합니다","기존","저장소의","색상","간격","프리셋은","자동","전환하지","않습니다","허브와","연결","화면은","vasthemestate","토큰을","사용하고","url","상태","브리지로","선택값을","이어갑니다"],"rank":1.0},{"id":"6d95d0fe362eacad","source":"docs/HANDOFF.md","title":"사용자용 AI 전달팩","line":3,"text":"기본 흐름은 `project-import.html → 폴더 선택/분석 → JSON 미리보기 → 전달팩 저장 및 프롬프트 복사`입니다.\n\n- 공통 파일명: `VAS-AI-HANDOFF.json`\n- 선택 파일: `VAS-AI-SOURCE.zip` (`START-HERE.md`, `PROMPT.md`, JSON, manifest, 검토 발췌, SHA-256)\n- 사용 대상: Codex, Claude, Antigravity 및 JSON 첨부가 가능한 코딩 도구\n- 실제 수정 기준: 사용자가 코딩 도구에서 연 원본 프로젝트 폴더\n- 제외: 절대 경로, 비밀값, 개인화 메모리, 비승인 파일 내용","keywords":["사용자용","ai","전달팩","기본","흐름은","project","import","html","폴더","선택","분석","json","미리보기","저장","프롬프트","복사","입니다","공통","파일명","vas","handoff","파일","source","zip"],"rank":1.0},{"id":"0819f135c2aca79d","source":"docs/HANDOFF.md","title":"개발 인계 기준","line":13,"text":"- 단일 작업 원본: `src/`, `docs/`, `scripts/`, `tests/`\n- 사용자 데이터: `workspace/`이며 Git·배포에서 제외\n- 배포 생성: `python scripts/build_release.py`\n- 기존 키 호환: `vasFavorites`, `vasThemeHistory`, `vasThemeTokens`, `vasCurrentPreset`\n- 모든 화면: 외부 CDN 없이 시스템 sans/mono 사용","keywords":["개발","인계","기준","단일","작업","원본","src","docs","scripts","tests","사용자","데이터","workspace","이며","git","배포에서","제외","배포","생성","python","build","release","py","기존"],"rank":1.0},{"id":"11c5cf31cdf02ae1","source":"docs/HANDOFF.md","title":"검증","line":21,"text":"```powershell\ngit status --short\nnpm.cmd run knowledge:check\nnpm.cmd run test:python\nnpm.cmd run test:browser\nnpm.cmd run test:package\n```\n\n10회 스트레스 테스트는 사용자가 명시한 경우에만 실행합니다. 릴리스 전 캐시·비밀·사용자 데이터가 스테이징되지 않았는지 확인합니다.","keywords":["검증","powershell","git","status","short","npm","cmd","run","knowledge","check","test","python","browser","package","10","스트레스","테스트는","사용자가","명시한","경우에만","실행합니다","릴리스","캐시","비밀"],"rank":1.0},{"id":"a475bda573483a99","source":"docs/import-existing-project.md","title":"가장 쉬운 방법","line":3,"text":"1. `Run-VAS-System.bat`를 실행합니다.\n2. 허브에서 **기존 프로그램 AI로 연결**을 누릅니다.\n3. 원래 프로그램 폴더를 선택하고 **안전하게 분석하기**를 누릅니다.\n4. 기술 스택, 파일 수, 제외 항목을 확인합니다.\n5. **분석 JSON** 또는 직접 고른 파일만 담는 **검토 소스 ZIP**을 선택합니다.\n6. 사용할 코딩 도구를 고르고 **AI 전달팩 만들기**를 누릅니다.\n7. 코딩 도구에서 원본 폴더를 연 뒤 `VAS-AI-HANDOFF.json`을 첨부하고 복사된 프롬프트를 붙여넣습니다.\n\nVAS가 코딩 도구 계정이나 API 키를 요구하거나 자동 전송하지 않습니다.","keywords":["가장","쉬운","방법","run","vas","system","bat","실행합니다","허브에서","기존","프로그램","ai","연결","누릅니다","원래","폴더를","선택하고","안전하게","분석하기","기술","스택","파일","제외","항목을"],"rank":1.0},{"id":"f057bc54f5858b1b","source":"docs/import-existing-project.md","title":"무엇이 들어가나요?","line":15,"text":"- 상대 경로 파일 목록, 기술 스택, 진입점, 안전하게 읽은 매니페스트 정보\n- 사용자가 적은 작업 요청\n- 등록 프로젝트에서 활성화된 요구사항·디자인·프로젝트 RAG의 미리보기 항목\n- 원본 폴더를 실제 수정 기준으로 사용하라는 공통 안내\n\n절대 경로, 개인화 메모리, `.env`, 키·토큰, Git 내부, 의존성, 캐시, 링크, 바이너리는 제외합니다. 검토 소스 ZIP은 사용자가 체크한 안전한 텍스트의 제한된 발췌만 담습니다.","keywords":["무엇이","들어가나요","상대","경로","파일","목록","기술","스택","진입점","안전하게","읽은","매니페스트","정보","사용자가","적은","작업","요청","등록","프로젝트에서","활성화된","요구사항","디자인","프로젝트","rag"],"rank":1.0},{"id":"102869f8a64c605f","source":"docs/import-existing-project.md","title":"웹판과 Windows판","line":24,"text":"- 웹판: 파일 이름과 크기로 내용 없는 분석 JSON을 만듭니다.\n- Windows판: 매니페스트 분석, 등록 프로젝트 RAG, JSON 재검증, 검토 소스 ZIP을 제공합니다.\n- 원본 소스가 분석 후 바뀌면 저장을 중단하고 다시 분석하도록 안내합니다.","keywords":["웹판과","windows","웹판","파일","이름과","크기로","내용","없는","분석","json","만듭니다","매니페스트","등록","프로젝트","rag","재검증","검토","소스","zip","제공합니다","원본","소스가","바뀌면","저장을"],"rank":1.0},{"id":"2082246ab76f658d","source":"docs/import-existing-project.md","title":"VAS 안으로 복사하려면","line":30,"text":"전달 내용 확인 화면 아래 **고급 기능**을 엽니다. 확인 후 백업 → staging 복사 → SHA-256 검증 → `workspace/projects/` 등록 순서로 진행합니다. 기본 AI 전달 흐름에는 복사가 필요하지 않습니다.\n\n가져오기 결과가 맞지 않으면 완료 화면의 롤백을 사용합니다. 원본에는 영향을 주지 않습니다.","keywords":["vas","안으로","복사하려면","전달","내용","확인","화면","아래","고급","기능","엽니다","백업","staging","복사","sha","256","검증","workspace","projects","등록","순서로","진행합니다","기본","ai"],"rank":1.0},{"id":"146f030341548672","source":"docs/index.md","title":"사용자 흐름","line":3,"text":"```text\nRun-VAS-System.bat\n  -> 로컬 서버 + 허브\n     -> 새 프로젝트 -> 요구사항 -> 디자인 -> 프로젝트 RAG -> 계속 작업\n     -> 기존 프로젝트 -> 읽기 전용 분석 -> AI 전달 JSON/검토 ZIP -> 코딩 도구\n     -> 고급 복사 -> 백업/복제/검증 -> 프로젝트 등록\n     -> 보관 ZIP -> 요구사항/토큰/RAG 메타/해시만 보관\n     -> 내 메모리 -> 동의/일시정지/삭제/내보내기\n```","keywords":["사용자","흐름","text","run","vas","system","bat","로컬","서버","허브","프로젝트","요구사항","디자인","rag","계속","작업","기존","읽기","전용","분석","ai","전달","json","검토"],"rank":1.0},{"id":"05c698713848b878","source":"docs/index.md","title":"구성","line":15,"text":"| 영역 | 역할 | 기준 파일 |\n|---|---|---|\n| 허브 | 첫 실행, 프로젝트 목록, 기능 연결 | `src/vas-hub.html` |\n| 신청서 | 요구사항 입력, 초안 복원, JSON 저장 | `src/client-application.html` |\n| 디자인 | 테마 편집과 상태 전달 | `src/design-controller.html` |\n| AI 전달 | 폴더 분석·JSON/검토 ZIP·프롬프트 복사 | `src/project-import.html`, `scripts/vas_agent_handoff.py` |\n| 개인화 | 동의 기반 이벤트와 추천 | `src/personalization-store.js` |\n| RAG | 로컬 지식 색인·검색·프롬프트 보강 | `src/rag-lite.js` |\n| 프로젝트 연결 | 화면 간 projectId·단계 전달 | `src/project-context.js` |\n| 공통 화면 | Editorial 토큰·프로젝트/RAG 상태 | `src/editorial-shell.css`, `src/project-rail.js` |\n| 프로젝트 API | 레지스트리 v2·디자인·안전 ZIP | `scripts/VAS.Projects.psm1` |\n| 런타임 | 토큰·동일 출처 보호 로컬 HTTP API | `scripts/Start-VAS.ps1` |\n| 마이그레이션 | 아카이브·해시·원자적 배치·롤백 | `scripts/vas_project_import.py` |\n| 전달 API | 선택/등록 프로젝트의 안전 분석·내보내기 | `scripts/VAS.AgentHandoff.psm1`, `scripts/VAS.Server.Handoff.ps1` |\n| 배포 | 재현 가능한 ZIP/Pages 생성 | `scripts/build_release.py` |","keywords":["구성","영역","역할","기준","파일","허브","실행","프로젝트","목록","기능","연결","src","vas","hub","html","신청서","요구사항","입력","초안","복원","json","저장","client","application"],"rank":1.0},{"id":"bf71c3da7f92f43d","source":"docs/index.md","title":"저장 위치","line":33,"text":"- 작업 원본: `src/`, `docs/`, `scripts/`, `tests/`\n- 사용자 프로젝트·가져오기 상태: `workspace/` (Git 제외)\n- Windows 개인화 메모리: `%LOCALAPPDATA%\\QUINTPACT\\VAS\\` (Git·배포 제외)\n- 로컬 체크포인트: `.vas_backups/` (Git 제외)\n- 생성 배포물: `dist/` (Git 제외)\n- 공개 배포에는 사용자 데이터와 메모리를 포함하지 않습니다.\n- AI 전달 JSON과 검토 소스 ZIP은 실행본 배포 ZIP·보관 ZIP과 서로 다른 산출물입니다.","keywords":["저장","위치","작업","원본","src","docs","scripts","tests","사용자","프로젝트","가져오기","상태","workspace","git","제외","windows","개인화","메모리","localappdata","quintpact","vas","배포","로컬","체크포인트"],"rank":1.0},{"id":"427bf53c3e119321","source":"docs/index.md","title":"운영 원칙","line":43,"text":"- 모든 기능은 외부 CDN 없이 동작합니다.\n- 저장소가 차단되거나 손상돼도 기본값으로 실행합니다.\n- AI 전달 분석은 원본 실행·쓰기 금지이며, 고급 복사는 별도 승인 후에만 씁니다.\n- 저장소 내부 배포 미러는 사용하지 않습니다. 배포본은 매번 원본에서 생성합니다.\n- 파일은 500줄 이하로 유지합니다.\n- 고정 커밋 번호나 고정 테스트 개수를 문서에 기록하지 않습니다.\n\n관련 문서: `docs/OPERATIONS.md`, `docs/MIGRATION.md`, `docs/import-existing-project.md`, `docs/HANDOFF.md`.","keywords":["운영","원칙","모든","기능은","외부","cdn","없이","동작합니다","저장소가","차단되거나","손상돼도","기본값으로","실행합니다","ai","전달","분석은","원본","실행","쓰기","금지이며","고급","복사는","별도","승인"],"rank":1.0},{"id":"d1f144274558adbd","source":"docs/INSTRUCTIONS.md","title":"VAS 2.6.2 개발 규칙","line":1,"text":"- HTML/CSS/Vanilla JS, Python, PowerShell만으로 경량 운영합니다.\n- 파일당 500줄 이하, 외부 CDN·원격 폰트 금지입니다.\n- 코어 원본은 `src/`, `docs/`, `scripts/`, `tests/`입니다.\n- 사용자 프로젝트와 메모리는 `workspace/`에만 저장하고 Git·배포에서 제외합니다.\n- 저장소 안에 배포 미러 복사본을 만들지 말고 `scripts/build_release.py`로 재현 가능한 배포물을 생성합니다.\n- 새 프로젝트와 기존 프로젝트 모두 `workspace/projects/<name>/`에 격리합니다.\n- 기존 프로젝트는 읽기 전용 분석 → 승인 → staging 복제 → 해시 검증 → 원자적 승격 순서만 허용합니다.\n- 개인화는 동의 기반이며 파일 내용, 비밀값, 절대 경로를 기록하지 않습니다.\n- 평소에는 `npm.cmd run test:python`과 `npm.cmd run test:browser`를 사용합니다.\n- `npm.cmd run test:release`의 10회 스트레스 검사는 명시적 요청 때만 실행합니다.\n\n시스템 구조는 `docs/index.md`, 가져오기 절차는 `docs/import-existing-project.md`, 운영 절차는 `docs/OPERATIONS.md`를 기준으로 합니다.","keywords":["vas","개발","규칙","html","css","vanilla","js","python","powershell","만으로","경량","운영합니다","파일당","500","이하","외부","cdn","원격","폰트","금지입니다","코어","원본은","src","docs"],"rank":1.0},{"id":"5e683aa059388519","source":"docs/MIGRATION.md","title":"마이그레이션 정책","line":1,"text":"마이그레이션은 AI 전달팩과 별도인 고급 기능입니다. VAS 2.6.2는 사용자가 선택한 경우에만 기존 프로그램을 `workspace/projects/`에 안전하게 복사하고 원본을 보존합니다.","keywords":["마이그레이션","정책","마이그레이션은","ai","전달팩과","별도인","고급","기능입니다","vas","사용자가","선택한","경우에만","기존","프로그램을","workspace","projects","안전하게","복사하고","원본을","보존합니다"],"rank":1.0},{"id":"0051ea5e8cfd271d","source":"docs/MIGRATION.md","title":"단계","line":5,"text":"1. **선택**: 사용자가 원본 프로젝트 폴더를 직접 선택합니다.\n2. **분석**: 읽기 전용으로 기술 스택, Git, 용량, 파일 수, 의존성, 의심 파일을 확인합니다.\n3. **승인**: 대상 이름, 제외 항목, Git 보존, RAG 색인 여부와 가져온 뒤 할 일을 사용자가 확인합니다.\n4. **체크포인트**: 파일 목록·SHA-256과 복구 자료를 생성합니다.\n5. **복제**: 임시 staging으로 복사하고 검증한 뒤 대상 폴더로 원자적으로 승격합니다.\n6. **등록**: 프로젝트 목록과 선택한 지식 색인에 연결하고 관리·개선·리디자인·업그레이드 목적에 맞는 다음 화면을 엽니다.\n7. **검증**: 원본 불변, 대상 해시, 진입점, 의존성 안내를 확인합니다.","keywords":["단계","선택","사용자가","원본","프로젝트","폴더를","직접","선택합니다","분석","읽기","전용으로","기술","스택","git","용량","파일","의존성","의심","파일을","확인합니다","승인","대상","이름","제외"],"rank":1.0},{"id":"6c8f79d6928970ba","source":"docs/MIGRATION.md","title":"안전 경계","line":15,"text":"- 분석 중 프로젝트 파일을 실행하지 않습니다.\n- `.git`, 의존성 폴더, 비밀 후보는 보고서에 별도 표시합니다.\n- 심볼릭 링크와 대상 폴더 밖으로 나가는 경로는 차단합니다.\n- 같은 이름의 대상이 있으면 덮어쓰지 않습니다.\n- 원본 삭제는 기본 흐름에 없고 별도 확인 문구가 필요합니다.","keywords":["안전","경계","분석","프로젝트","파일을","실행하지","않습니다","git","의존성","폴더","비밀","후보는","보고서에","별도","표시합니다","심볼릭","링크와","대상","밖으로","나가는","경로는","차단합니다","같은","이름의"],"rank":1.0},{"id":"2ab51c8b9f2bbe8c","source":"docs/MIGRATION.md","title":"CLI","line":23,"text":"```powershell\npython scripts/vas-project-import.py analyze \"C:\\path\\old-project\"\npython scripts/vas-project-import.py import \"C:\\path\\old-project\" --name my-project\npython scripts/vas-project-import.py rollback <job-id>\n```\n\n정확한 옵션은 `python scripts/vas-project-import.py --help`로 확인합니다. 일반 사용자는 **기존 프로그램 AI로 연결** 화면 아래의 고급 기능을 사용합니다.","keywords":["cli","powershell","python","scripts","vas","project","import","py","analyze","path","old","name","my","rollback","job","id","정확한","옵션은","help","확인합니다","일반","사용자는","기존","프로그램"],"rank":1.0},{"id":"3a8a38b62b273f25","source":"docs/OPERATIONS.md","title":"실행","line":3,"text":"- 일반 사용자: `Run-VAS-System.bat` 더블클릭\n- 수동 실행: `powershell -ExecutionPolicy Bypass -File scripts/Start-VAS.ps1`\n- 종료: 사용하지 않으면 기본 30분 뒤 자동 종료; 즉시 종료는 인증된 `/api/shutdown` 사용\n\nWindows판의 AI 전달 분석·검토 소스 ZIP·기존 프로젝트 복사는 Python 3.10 이상을 사용합니다. Python이 없으면 화면에서 안내하며 웹판의 내용 없는 분석 JSON과 나머지 기능은 계속 사용할 수 있습니다.\n\n서버는 `127.0.0.1`에만 바인딩하고, 시작할 때 만든 세션 토큰과 동일 출처 요청만 허용합니다. 토큰을 URL에서 받은 뒤 세션 저장소로 옮기고 주소에서는 제거합니다.","keywords":["실행","일반","사용자","run","vas","system","bat","더블클릭","수동","powershell","executionpolicy","bypass","file","scripts","start","ps1","종료","사용하지","않으면","기본","30","자동","즉시","종료는"],"rank":1.0},{"id":"43e81956fed636ae","source":"docs/OPERATIONS.md","title":"저장과 복구","line":13,"text":"- 프로젝트: `workspace/projects/`\n- 가져오기 작업·프로젝트 등록·프로젝트 RAG: `workspace/.vas/`\n- 코어 체크포인트: `.vas_backups/checkpoint_*.zip` 최신 10개\n- 가져오기 복구본: `.vas_backups/migrations/` (사용자가 정리하기 전까지 보존)\n- Windows 개인화 메모리·런타임 세션: `%LOCALAPPDATA%\\QUINTPACT\\VAS\\`\n- 브라우저 전용 개인화 메모리: IndexedDB\n\n가져오기 전 체크포인트와 파일 해시를 생성합니다. 실패한 작업은 staging을 제거하며 완료 작업은 작업 ID로 되돌릴 수 있습니다.","keywords":["저장과","복구","프로젝트","workspace","projects","가져오기","작업","등록","rag","vas","코어","체크포인트","backups","checkpoint","zip","최신","10","복구본","migrations","사용자가","정리하기","전까지","보존","windows"],"rank":1.0},{"id":"5488bf172bcf4570","source":"docs/OPERATIONS.md","title":"개인정보","line":24,"text":"- 기본값은 수집 안 함입니다.\n- 동의 전 이벤트를 기록하지 않습니다.\n- 비밀값, 파일 내용, 절대 경로, 파일명은 이벤트에 저장하지 않습니다.\n- 새 프로젝트 RAG는 연락처·이름·원본 brief를 제외한 `rag-context.json`만 색인합니다.\n- 가져온 프로젝트 RAG는 가져오기 때 별도로 선택한 경우에만 허용된 텍스트를 로컬 색인합니다.\n- 프로젝트 지식 API는 `projectId`가 없으면 거부하며 다른 프로젝트의 결과를 섞지 않습니다.\n- 기록은 사용자가 직접 일시정지·삭제·내보내기·가져오기 합니다.\n- 자동 만료나 조용한 삭제를 하지 않습니다.\n- 신청서 초안은 복구를 위해 브라우저에 자동 저장됨을 화면에 표시하며, 사용자가 끄거나 삭제할 수 있고 JSON 저장·작업공간 생성 뒤에는 지웁니다.","keywords":["개인정보","기본값은","수집","함입니다","동의","이벤트를","기록하지","않습니다","비밀값","파일","내용","절대","경로","파일명은","이벤트에","저장하지","프로젝트","rag","연락처","이름","원본","brief","제외한","context"],"rank":1.0},{"id":"c929725405817f1d","source":"docs/OPERATIONS.md","title":"검증","line":36,"text":"```powershell\nnpm.cmd ci\npython -m pip install -r tests/requirements-dev.txt\nnpm.cmd run knowledge:check\nnpm.cmd run test:python\nnpm.cmd run test:browser\nnpm.cmd run test:package\n```\n\n`npm.cmd run test:release`에는 10회 반복이 포함되므로 사용자가 명시한 릴리스 검증에서만 실행합니다.","keywords":["검증","powershell","npm","cmd","ci","python","pip","install","tests","requirements","dev","txt","run","knowledge","check","test","browser","package","release","에는","10","반복이","포함되므로","사용자가"],"rank":1.0},{"id":"6f3a429a23b2ad79","source":"docs/OPERATIONS.md","title":"프로젝트 인계","line":49,"text":"허브의 **AI 전달팩**은 코딩 도구용 분석 JSON과 선택적 검토 발췌를 만듭니다. **보관 ZIP**은 `project.json`, 정제 요구사항, 디자인 토큰, RAG 제목·키워드·상대 경로, 해시만 포함합니다. 어느 쪽에도 `.env`, 절대 경로, 개인화 메모리 이벤트를 넣지 않습니다.","keywords":["프로젝트","인계","허브의","ai","전달팩","코딩","도구용","분석","json","선택적","검토","발췌를","만듭니다","보관","zip","project","정제","요구사항","디자인","토큰","rag","제목","키워드","상대"],"rank":1.0},{"id":"a0f429fd6891dfab","source":"docs/OPERATIONS.md","title":"배포","line":53,"text":"`npm.cmd run release:build` 후 `dist/SHA256SUMS.txt`와 각 ZIP 내부 `manifest.json`을 확인합니다. 배포 ZIP에는 `.git`, `workspace`, 백업, 캐시, 테스트 결과, 환경 변수, 개인화 데이터가 들어가면 안 됩니다.","keywords":["배포","npm","cmd","run","release","build","dist","sha256sums","txt","zip","내부","manifest","json","확인합니다","에는","git","workspace","백업","캐시","테스트","결과","환경","변수","개인화"],"rank":1.0},{"id":"880a8c87fcc5f0e4","source":"docs/OPERATIONS.md","title":"장애 확인 순서","line":57,"text":"1. `Run-VAS-System.bat`의 오류 문구를 확인합니다.\n2. `/health`가 응답하는지 확인합니다.\n3. `npm.cmd run test:python`으로 파일·API 계약을 확인합니다.\n4. 가져오기 실패는 작업 ID로 rollback하고 원본 해시가 유지됐는지 확인합니다.","keywords":["장애","확인","순서","run","vas","system","bat","오류","문구를","확인합니다","health","응답하는지","npm","cmd","test","python","파일","api","계약을","가져오기","실패는","작업","id","rollback"],"rank":1.0},{"id":"149bb39e81be5b6e","source":"docs/releases/2.6.1.md","title":"VAS 2.6.1","line":1,"text":"프로젝트가 화면마다 끊기지 않도록 새 프로젝트·기존 프로그램·디자인·RAG·안전 인계를 하나의 흐름으로 연결했습니다.","keywords":["vas","프로젝트가","화면마다","끊기지","않도록","프로젝트","기존","프로그램","디자인","rag","안전","인계를","하나의","흐름으로","연결했습니다"],"rank":1.0},{"id":"413defce69bd2146","source":"docs/releases/2.6.1.md","title":"주요 변경","line":5,"text":"- Awwwards Editorial 기준의 공통 데스크톱·모바일 레이아웃\n- 프로젝트 컨텍스트와 레지스트리 v2 단계 복원\n- 현재 프로젝트에만 한정된 동의 기반 자동 RAG\n- 기존 프로그램 분석·복제·색인 선택 흐름 개선\n- 원본 소스와 비밀값을 제외한 안전 인계 ZIP\n- 320px부터 데스크톱까지 반응형·키보드·저장소 실패 검증","keywords":["주요","변경","awwwards","editorial","기준의","공통","데스크톱","모바일","레이아웃","프로젝트","컨텍스트와","레지스트리","v2","단계","복원","현재","프로젝트에만","한정된","동의","기반","자동","rag","기존","프로그램"],"rank":1.0},{"id":"d6598ab0d7aff6fe","source":"docs/releases/2.6.1.md","title":"호환성","line":14,"text":"기존 테마 키와 색상·간격 값은 유지합니다. 레거시 폰트 값만 오프라인 시스템 글꼴로 정규화합니다. `v2.6.0` 태그와 외부 백업은 그대로 보존합니다.","keywords":["호환성","기존","테마","키와","색상","간격","값은","유지합니다","레거시","폰트","값만","오프라인","시스템","글꼴로","정규화합니다","v2","태그와","외부","백업은","그대로","보존합니다"],"rank":1.0},{"id":"21ca37982db3c8f6","source":"docs/releases/2.6.2.md","title":"VAS 2.6.2","line":1,"text":"기존 프로그램을 복사하지 않고도 코딩 AI에 안전하게 연결하는 AI 전달팩 흐름을 추가했습니다.","keywords":["vas","기존","프로그램을","복사하지","않고도","코딩","ai","안전하게","연결하는","전달팩","흐름을","추가했습니다"],"rank":1.0},{"id":"ab3eae65e48bcdc6","source":"docs/releases/2.6.2.md","title":"주요 변경","line":5,"text":"- 폴더 선택 → 읽기 전용 분석 → 전달 범위 확인 → JSON/ZIP 저장과 프롬프트 복사\n- Codex·Claude·Antigravity에 공통으로 쓰는 `VAS-AI-HANDOFF.json`\n- 사용자가 직접 고른 텍스트 발췌만 담는 검토 소스 ZIP\n- 등록 프로젝트의 요구사항·디자인·활성 RAG 연결, 개인화 메모리 기본 제외\n- 기존 복사 마이그레이션을 고급 기능으로 유지\n- Awwwards Editorial 기준의 비대칭 3영역 데스크톱·모바일 레이아웃\n- 절대 경로·Git 내부·캐시·비밀값·링크·바이너리 차단과 원본 변경 재검증\n\n기존 진입점, 테마 저장 키, 프로젝트 레지스트리와 2.6.1 백업은 그대로 호환됩니다.","keywords":["주요","변경","폴더","선택","읽기","전용","분석","전달","범위","확인","json","zip","저장과","프롬프트","복사","codex","claude","antigravity","공통으로","쓰는","vas","ai","handoff","사용자가"],"rank":1.0}]});
})(typeof window!=='undefined'?window:globalThis);
